INSERT INTO questions (day, type, question, options, answer, explanation) VALUES
  (1, 'practice', '根据PPT内容，思维是指人们在工作、学习、生活中每逢遇到问题，总要''想一想''的能力。这种能力主要通过哪些过程来解决问题？', '["记忆、背诵、抄写、重复练习","分析、综合、概括、抽象、比较、具体化和系统化","听讲、记录、模仿、考试","观察、实验、测量、计算"]', 1, '正确答案是B。根据PPT原文：''思维是通过分析、综合、概括、抽象、比较、具体化和系统化等一系列过程，解决问题并运用到生活其它场景中去的能力。''课程顾问话术：''思维能力强的孩子，遇到问题时不会只会一种解法，而是会「想一想」有没有更好的方式。比如洗衣服20分钟、烧开水10分钟、扫地5分钟，普通孩子花35分钟，但思维好的孩子会安排并行处理，只要20分钟。这就是思维带来的效率差异。'''),
  (1, 'practice', 'PPT中提到思维能力包含六个维度，以下哪个选项完整且正确地列出了这六个维度？', '["记忆力、理解力、应用力、分析力、评价力、创造力","敏捷性、灵活性、创造性、系统性、批判性、深刻性","注意力、观察力、想象力、思维力、表达力、实践力","逻辑力、推理力、判断力、决策力、执行力、领导力"]', 1, '正确答案是B。PPT原文明确指出思维能力包含：敏捷性、灵活性、创造性、系统性、批判性、深刻性。课程顾问话术：''我们培养的不是做题机器，而是具备六大思维品质的孩子——反应快（敏捷性）、方法多（灵活性）、点子新（创造性）、有条理（系统性）、会质疑（批判性）、看得深（深刻性）。'''),
  (1, 'practice', 'VIPThink课程主要面向哪个年龄段的孩子，并以什么模型为框架设计？', '["6-18岁，以STEM教育模型为框架","3-12岁，以21世纪核心素养5C模型为框架","5-15岁，以多元智能理论为框架","4-14岁，以布鲁姆教育目标分类为框架"]', 1, '正确答案是B。PPT原文：''VIP Think为3-12岁少儿提供思维素质课程''，''围绕21世纪核心素养5C模型''。课程顾问话术：''VIPThink不只是数学课，而是面向3-12岁孩子的思维素质课。我们参照国际认可的21世纪核心素养5C模型设计，让孩子在未来社会具备核心竞争力。'''),
  (1, 'practice', 'VIPThink课程包含哪五大内容模块？', '["语文阅读、数学计算、英语听说、科学实验、艺术创作","益智策略、数与代数、空间几何、逻辑推理、生活应用","编程思维、机器人制作、3D打印、虚拟现实、人工智能","阅读理解、写作表达、口语交际、听力训练、语法学习"]', 1, '正确答案是B。PPT原文明确列出五大模块：''益智策略、数与代数、空间几何、逻辑推理、生活应用''。课程顾问话术：''我们的课程涵盖五大模块：益智策略锻炼脑力、数与代数打牢基础、空间几何培养想象力、逻辑推理训练严谨性、生活应用让知识落地。五大能力全面发展，不是只学计算。'''),
  (1, 'practice', 'VIPThink课程旨在培养孩子哪五大能力？', '["听说读写算","逻辑推理能力、策略分析能力、模型建构能力、生活应用能力、实践创新能力","记忆力、注意力、观察力、想象力、思维力","自主学习、合作学习、探究学习、创新学习、终身学习"]', 1, '正确答案是B。PPT原文：''培养孩子逻辑推理能力、策略分析能力、模型建构能力、生活应用能力和实践创新能力共五大能力''。课程顾问话术：''上完我们的课程，孩子将获得五大核心能力：逻辑推理能力让思考有依据、策略分析能力让解题有方法、模型建构能力让知识成体系、生活应用能力让学习有价值、实践创新能力让想法能落地。'''),
  (1, 'practice', '课程三维培养目标中的''三大思维''具体指什么？', '["形象思维、抽象思维、辩证思维","分析-批判性思维、实用-情境性思维、创造-综合性思维","线性思维、发散思维、聚合思维","直觉思维、逻辑思维、创新思维"]', 1, '正确答案是B。PPT原文：''三大思维：分析-批判性思维、实用-情境性思维、创造-综合性思维''。课程顾问话术：''我们的课程培养三大思维：批判性思维让孩子学会分析判断，情境性思维让孩子能结合实际，综合性思维让孩子善于创造。这三种思维是孩子未来学习和工作的底层能力，而奥数课主要训练解题技巧，不强调思维品质。'''),
  (1, 'practice', '课程三维培养目标包括哪三个维度？', '["知识目标、能力目标、情感目标","核心内容掌握、思维能力培养、行为情感的构建","认知目标、技能目标、态度目标","学科目标、学段目标、学期目标"]', 1, '正确答案是B。PPT原文：''三维目标：核心内容掌握、思维能力培养、行为情感的构建''。课程顾问话术：''我们的教学目标有三个层面：不只是教会孩子知识（核心内容），更重要的是培养思维能力，同时关注孩子的行为习惯和情感态度。这才是完整的教育，而不是只盯着分数。'''),
  (1, 'practice', '课程效果通过哪三大外化表现来体现？', '["成绩提高、排名上升、竞赛获奖","爱思考、善表达、会应用","听话懂事、勤奋刻苦、尊敬师长","作业完成快、考试分数高、课堂表现好"]', 1, '正确答案是B。PPT原文：''三大外化：爱思考、善表达、会应用''。课程顾问话术：''学习效果看三个外化表现：孩子是不是更爱思考了？能不能清楚表达自己的想法？能不能把学到的东西应用到生活中？这才是真正的学习成果，而不是只看考试分数。'''),
  (1, 'practice', '关于数学思维内容的三层构建，以下哪个选项正确描述了这三层？', '["基础层、进阶层、挑战层","底层-认知层、中层-方法层、上层-应用层","输入层、加工层、输出层","感知层、理解层、运用层"]', 1, '正确答案是B。PPT原文：''底层-认知层、中层-方法层、上层-应用层''。课程顾问话术：''我们的课程像盖房子一样有三层结构：底层打地基，培养注意控制、空间表征、工作记忆等基础认知能力；中层建框架，通过五大模块学习具体方法；上层做装修，让孩子综合运用解决实际问题。层层递进，稳扎稳打。'''),
  (1, 'practice', '根据PPT中的皮亚杰认知发展阶段理论，7-11岁的孩子处于哪个思维发展阶段？', '["直觉行动思维阶段","具体形象思维阶段","抽象逻辑思维萌芽阶段","抽象逻辑思维阶段"]', 2, '正确答案是C。PPT原文：''7-11岁 抽象逻辑思维萌芽''。课程顾问话术：''根据儿童心理学家皮亚杰的研究，孩子的思维发展是有规律的：0-2岁靠动作思考，2-7岁靠具体形象思考，7-11岁开始有抽象逻辑萌芽，11-16岁才发展成熟。我们的课程就是根据这个规律，在合适的年龄给孩子合适的内容，不会拔苗助长。'''),
  (1, 'practice', 'VIPThink的班型模式有哪些核心特点？', '["大班录播、自主学习、无老师跟进","6-8人小班直播、专属VIP服务、课前课中课后闭环、授课老师全程跟进","一对一私教、定制化课程、高价服务","线下实体课堂、固定教室、固定时间"]', 1, '正确答案是B。PPT原文：''6-8人小班直播，专属VIP服务''、''授课老师全程跟进''、''课前课中课后闭环''。课程顾问话术：''我们采用6-8人小班直播，老师能关注到每个孩子。专属VIP服务意味着课前课中课后形成完整闭环，还有在线线下拓展练习，家长不用操心，学习效果有保障。小班直播比大班录播互动性强，比一对一性价比高。'''),
  (1, 'practice', '关于''不系统''这个痛点，PPT指出常规学习存在什么问题？', '["教材版本不统一","学习方法缺乏提炼，孩子没有形成有效的思维体系，只会机械地学习，学习效率低","学校老师换得太频繁","课程进度太快"]', 1, '正确答案是B。PPT原文：''学习方法缺乏提炼，孩子没有形成有效的思维体系，只会机械地学习，学习效率低''。课程顾问话术：''传统教育把知识切割到不同单元、不同学段，衔接性低。孩子得到零件（知识），却没有说明书（方法）。我们的课通过思考工具、模型建构掌握方法，通过问题实践让知识提升到应用层面，孩子懂得反思和总结，形成自己的思维体系。'''),
  (1, 'practice', 'PPT中''不会用''这个痛点具体指什么？', '["孩子不愿意做作业","只能浅层理解，学完就忘；换一道题就不会做了；一类题目只有一种解法，应对问题缺乏弹性，应用能力不足","孩子上课不认真听讲","家长不会辅导"]', 1, '正确答案是B。PPT原文：''只能浅层理解，学完就忘；换一道题就不会做了；一类题目只有一种解法，应对问题缺乏弹性，应用能力不足''。课程顾问话术：''传统学习只能浅层理解，学完就忘。我们的课通过综合的应用提升理解，重视方法总结，找到问题的共性，应对不同难题；引导多维度思考，打开思路，做到举一反三。孩子学会的是方法，不是死记硬背的套路。'''),
  (1, 'practice', 'VIPThink如何解决''不喜欢''（兴趣不足）的问题？', '["通过游戏和动画吸引孩子","以问题情景导入，让孩子有参与感；产品化的辅助功能让抽象问题具体呈现，从0到1步步引导","给物质奖励和积分","强制孩子上课"]', 1, '正确答案是B。PPT原文：''以问题情景导入，让孩子有参与感。产品化的辅助功能，让抽象问题具体呈现，从0到1步步引导，理解了就不畏难''。课程顾问话术：''我们的课以问题情景导入，比如以旅行为主题，让孩子规划旅行路线、计算预算，孩子有参与感。产品化的辅助功能让抽象问题具体呈现，从0到1步步引导，理解了就不畏难，主动性自然就提高了。'''),
  (1, 'practice', 'VIPThink如何帮助孩子建立系统的思维体系？', '["让孩子做大量练习题","通过思考工具、模型建构掌握方法，通过问题实践让知识提升到应用层面，懂得反思和总结","背诵公式和定理","参加竞赛和考试"]', 1, '正确答案是B。PPT原文：''通过思考工具、模型建构掌握方法，通过问题实践让知识提升到应用层面，懂得反思和总结，形成自己的思维体系''。课程顾问话术：''孩子通过「询问分析表」、「维度打分表」等思考工具掌握方法，通过旅行计划、预算规划等问题实践让知识提升到应用层面。每节课后还有反思总结，逐步形成自己的思维体系，不是机械学习。'''),
  (1, 'practice', 'VIPThink如何培养孩子的应用能力和举一反三的能力？', '["布置大量家庭作业","通过综合的应用提升理解，重视方法总结，找到问题的共性，引导多维度思考","要求孩子背诵解题步骤","只做课本上的例题"]', 1, '正确答案是B。PPT原文：''通过综合的应用提升理解，重视方法总结，找到问题的共性，应对不同难题；引导多维度思考，打开思路，做到举一反三''。课程顾问话术：''比如孩子学了「最优解」的方法，不仅能解决数学中的最值问题，还能在生活中规划最短路线、最省钱的购物方案。我们重视方法总结，找到问题共性，孩子学会的是解决一类问题的方法，不是一道题的答案。'''),
  (1, 'practice', 'VIPThink台湾学员的授课老师有什么特殊优势？', '["都是台湾本地老师，熟悉台湾教材","专门负责VIPThink台湾学员，熟悉台湾孩子的学习习惯和思考方式","都有留学背景，英语流利","都是名校毕业，学历很高"]', 1, '正确答案是B。PPT原文：''我们的授课老师都是专门负责VIPThink台湾学员的，班级也是专为台湾学生量身打造的，所以非常熟悉台湾孩子的学习习惯跟思考方式''。课程顾问话术：''我们的老师都是专门服务台湾学员的，非常了解台湾孩子的学习习惯和思考模式，能精准对应孩子的学习需求。家长可以放心，孩子的学习效果一定没问题的！'''),
  (1, 'practice', 'S1-S2级别的班级人数是多少？', '["8-10人/班","4-6人/班","10-12人/班","2-3人/班"]', 1, '正确答案是B。PPT原文：''S1-S2 4-6人/班''。课程顾问话术：''S1-S2是4-6人小班，因为低龄孩子注意力时间短，需要老师更多关注和互动。小班制确保每个孩子都有表达机会，老师能及时发现孩子的困惑并调整教学。等孩子到了S3以上，适应力增强，班级人数才增加到6-8人。'''),
  (1, 'practice', 'S1级别的课程时长是多少？', '["45分钟/节","30分钟/节","60分钟/节","20分钟/节"]', 1, '正确答案是B。PPT原文：''S1 30min/节''。课程顾问话术：''S1只有30分钟，这是根据低龄孩子注意力特点科学设置的。5-6岁孩子有效注意力通常只有15-20分钟，30分钟的课程能保证在注意力最集中的时段完成核心内容，不会让孩子感到疲惫。S2以上逐步增加到40-45分钟，循序渐进培养专注力。'''),
  (1, 'practice', 'VIPThink的退费政策中，无忧试学的期限和条件是什么？', '["2节课内，全额退","4节课内，全额退","1节课内，全额退","6节课内，全额退"]', 1, '正确答案是B。PPT原文：''4节课内：无忧试学，全额退''。课程顾问话术：''我们有非常宽松的退费政策：前4节课不满意全额退款，零风险试学。如果之后退费，按实际剩余课时计算，7-14个工作日原路退回。我们对课程质量有信心，所以敢这样承诺。您可以让孩子先体验，完全没有后顾之忧。'''),
  (1, 'practice', '如果购买价格是12000元，基础直播课时96节，已上10节课后申请退费，应退还多少金额？', '["12000 - (12000/96)*10 = 10750元","12000元（全额退）","12000/96*10 = 1250元","12000 - 12000/4 = 9000元"]', 0, '正确答案是A。PPT原文：''购买价格/基础直播课时*剩余课时=退还金额''。计算：12000/96*(96-10)=125*86=10750元。课程顾问话术：''退费计算很透明：购买价格除以总课时，得到每节课单价，再乘以剩余课时就是退款金额。比如您买12000元96节课，上了10节想退，每节125元，剩余86节，退款10750元。7-14个工作日原路退回，不需要跑手续，OA系统直接申请。'''),
  (1, 'practice', '退费申请通过后，退款到账需要多长时间？', '["1-3个工作日","7-14个工作日","15-30个工作日","1-2个月"]', 1, '正确答案是B。PPT原文：''退费时间：7-14个工作日内原路退还''。课程顾问话术：''退款7-14个工作日内原路退回您的支付账户，不需要您跑银行或填表格。而且前4节课是全额退，零风险试学。我们敢这样承诺，就是对课程质量有绝对信心。您先让孩子体验，满意了再继续，完全没有后顾之忧。'''),
  (1, 'practice', '《课后拓展练习》的主要功能是什么？', '["记录孩子上课表现","与直播课程一一搭配，提供详细专家解析和小老师视频操作指导","家长交流社区","在线作业批改"]', 1, '正确答案是B。PPT原文：''vipthink配套《课后拓展练习》，与直播课程一一搭配，提供详细专家解析和小老师视频操作指导''。课程顾问话术：''课后配套《课后拓展练习》，和课堂内容完全同步。里面有专家详细解析，还有小老师视频一步步教，孩子回家复习不费力，家长辅导没压力。就算家长不懂数学，孩子也能自主复习。'''),
  (1, 'practice', '新版教材相比旧版有哪些改进？', '["增加了更多练习题","立足于学生学习综合发展需求，在丰富多样的情境中深度思考、拓展思维广度，还能帮助了解科普知识，养成阅读习惯","减少了内容难度","增加了考试模拟题"]', 1, '正确答案是B。PPT原文：''新版教材将进一步立足于学生的学习综合发展需求，让学生能够有效复习，巩固课堂所学的方法和策略，在丰富多样的情境中深度思考、拓展思维广度；此外，它还能帮助学生了解更加丰富的科普知识，养成阅读好习惯''。课程顾问话术：''新版教材不只是习题册，而是综合学习手册。它在丰富情境中让孩子深度思考，拓展思维广度；还融入科普知识，培养阅读习惯。孩子复习的不只是数学，更是综合素养。'''),
  (1, 'practice', 'VIPThink如何帮助孩子进行专题复习？', '["每个单元结束提供单元测试","每个专题结束，提供专题复习，为学生回顾总结提供路径和方法；预约课堂，一键补课","每月一次综合考试","期末统一复习"]', 1, '正确答案是B。PPT原文：''每个专题结束，提供专题复习，为学生回顾总结提供路径和方法。预约课堂，一键补课，让学生不漏掉任何一节精彩课堂''。课程顾问话术：''每个专题结束都有专题复习课，帮孩子梳理知识脉络，总结方法路径。如果缺课还能一键补课，不会漏掉任何内容。这样周期性回顾，孩子学得更扎实，不容易遗忘。'''),
  (1, 'practice', 'VIPThink的课程回放功能包含哪些特点？', '["只有音频回放","下课后系统生成课程回放，动画视频总结，家长能实时看到孩子上课时最自然的表现情况","需要额外付费才能观看","只有文字记录"]', 1, '正确答案是B。PPT原文：''下课后，系统生成课程回放，孩子和家长都能方便快捷地回顾''、''动画视频总结，课后随时回顾''、''家长能实时看到孩子上课时最自然的表现情况''。课程顾问话术：''每节课都有回放，孩子可以随时复习。还有动画视频总结重点，生动有趣。家长还能实时看到孩子上课的真实表现，不是刻意表演的样子，而是最自然的学习状态。学习报告数据化呈现，孩子学得怎么样一目了然。'''),
  (1, 'practice', 'VIPThink为家长提供哪些额外服务？', '["只提供课程，不提供家长服务","家庭教育以及思维训练方法的指导，快乐分享最新教育资讯","只提供课程回放","只提供教材"]', 1, '正确答案是B。PPT原文：''家庭教育以及思维训练方法的指导，快乐分享最新教育资讯''。课程顾问话术：''我们不只是教孩子，还教家长。提供家庭教育指导和思维训练方法，分享最新教育资讯。家长学会科学陪伴方法，在家也能延续课堂效果。教育不是学校单方面的事，家校配合才能最大化效果。'''),
  (1, 'practice', 'S1级别的课程环节设置有什么特点？', '["S1有基础认知、方法、应用三个环节","S1重认知和方法，所以S1只有环节1：基础认知","S1没有固定环节，随意教学","S1只有应用环节"]', 1, '正确答案是B。PPT原文：''*S1重认知和方法，所以S1只有环节1：基础认知''。课程顾问话术：''S1只有基础认知环节，因为低龄孩子需要先建立基本概念和认知框架。就像盖房子要先打地基，不能急着往上盖。S2以上才增加方法+应用环节，循序渐进，符合孩子认知发展规律。'''),
  (1, 'practice', 'VIPThink课程环节设置的第一个目的是什么？', '["降低教学成本","质量保证，是课程质量的保护盾，规范教研制作和教学输出，支持3000名老师在统一标准下授课","增加课程时长","减少老师工作量"]', 1, '正确答案是B。PPT原文：''质量保证：是课程质量的保护盾，规范教研制作和教学输出，支持3千名老师在统一标准下授课，推进全球课程同步''。课程顾问话术：''我们的课程有严格的环节标准，全球3000名老师统一执行。无论孩子在台北还是高雄，上的课品质都一样。这是课程质量的「保护盾」，家长不用担心老师水平参差不齐。'''),
  (1, 'practice', 'VIPThink课程环节设置的第二个目的是什么？', '["让孩子自由玩耍","足够开放，培养思维弹性；重视个性化提问和一题多问的开放式引导，摆脱传统教育的刻板印象","减少老师备课时间","统一教学进度"]', 1, '正确答案是B。PPT原文：''足够开放，培养思维弹性：重视个性化提问和一题多问的开放式引导，摆脱传统教育的刻板印象，方式灵活、有趣、开放''。课程顾问话术：''传统教育追求标准答案，我们的课堂是开放式引导。一道题可能有多种解法，鼓励孩子个性化思考。比如「旅行计划」没有唯一正确答案，孩子要考虑预算、时间、兴趣多个维度，做出自己的最优决策。这样培养出来的孩子思维灵活，不会死板。'''),
  (1, 'practice', '当家长说''你们这和奥数有什么区别？''时，以下哪种话术最能准确传达VIPThink与奥数的本质区别？', '["''我们比奥数更难，更适合聪明孩子''","''奥数侧重解题技巧和竞赛套路，我们侧重思维品质培养、方法工具掌握和实际应用能力，培养的是底层能力而非应试技巧''","''我们比奥数便宜''","''奥数是骗人的，我们是正规的''"]', 1, '正确答案是B。综合PPT核心理念：VIPThink培养思维品质（敏捷性、灵活性、创造性、系统性、批判性、深刻性）、方法工具（思考工具、模型建构）和实际应用（生活应用、实践创新），而非奥数式的解题套路和竞赛技巧。课程顾问话术：''奥数侧重解题技巧和竞赛套路，训练的是「做题能力」；我们侧重思维品质培养、方法工具掌握和实际应用能力，培养的是「底层思维能力」。简单说，奥数教的是「这道题怎么做」，我们教的是「遇到新问题怎么思考」。孩子学会的是可迁移的方法，不是死记硬背的套路。'''),
  (2, 'practice', '课程顾问在开场白中，应该向家长表明自己的什么身份？', '["VIP THINK的X老师，专门负责对接的顾问老师","VIP THINK的销售人员","VIP THINK的上课老师","VIP THINK的客服人员"]', 1, '无'),
  (2, 'practice', '开场白中提到''为了给孩子安排最合适孩子的老师和课件''，这句话的主要目的是什么？', '["展示公司的师资力量","为后续探需做铺垫，让家长愿意配合回答问题","强调课件的重要性","说明课程价格很高"]', 1, '无'),
  (2, 'practice', '探需环节中，以下哪项不属于需要了解的基本信息？', '["孩子姓名","家庭经济状况","数学基础","性格特点"]', 1, '无'),
  (2, 'practice', '以下哪句话术适合在询问孩子数学基础时使用？', '["您家孩子数学好吗？","小朋友目前10以内/20以内/50以内/100以内的加减法掌握程度如何？能不能认图形呢？","您家孩子是不是数学很差？","孩子上过补习班吗？"]', 1, '无'),
  (2, 'practice', '探需时询问''上课常用语言（中/英/中英双语）''的主要目的是什么？', '["了解家长的语言偏好","为孩子匹配合适的老师和课件","判断家长的经济能力","统计市场数据"]', 1, '无'),
  (2, 'practice', '当家长表示孩子''坐不住、容易分心''时，以下哪句回应最恰当？', '["那您应该好好管教孩子","这类孩子其实反应很快，就是需要更有趣的方式吸引他。我们课堂节奏轻快、互动多，每几分钟就有小任务，老师全程引导参与，孩子不容易分心","这样的孩子不适合线上课","我们课程很严格，能让孩子安静下来"]', 1, '无'),
  (2, 'practice', '询问孩子有无线上课程学习经验的主要目的是什么？', '["判断家长是否有钱","为后续打预防针和对比线下做铺垫","了解孩子的学习能力","统计课程市场占有率"]', 1, '无'),
  (2, 'practice', '探需环节中，顾问应该秉持的核心理念是什么？', '["尽快推销课程","尽早发现顾虑和问题，先解决，为课后截杀做准备","让家长感受到压力","展示顾问的专业知识"]', 1, '无'),
  (2, 'practice', '当孩子性格属于''外向活泼''型时，以下哪句话术最恰当？', '["外向活泼的孩子上课会打扰别人，需要管教","小朋友这么爱互动、爱表达，是很大的优势，我们会引导他把这份积极性转化为专注度，学会有条理地表达思路","外向的孩子不适合我们的课程","我们会让孩子安静下来，不要那么活泼"]', 1, '无'),
  (2, 'practice', '当孩子性格属于''内向慢热''型时，顾问应该如何回应？', '["内向的孩子需要逼迫他们发言","我们不会催促小朋友发言，会用温和的提问、耐心的鼓励，慢慢帮他建立自信，让他慢慢放开自己，敢主动表达、愿参与课堂","内向的孩子不适合小班互动课","我们会安排一对一课程"]', 1, '无'),
  (2, 'practice', '当孩子是''急性子''时，以下哪句话术最能体现课程价值？', '["急性子的孩子需要严厉管教","我们会通过课堂小任务，引导他学会沉下心、一步一步解题，培养细心、沉稳的习惯，避免急躁粗心","急性子的孩子学不好数学","我们会加快课程节奏配合孩子"]', 1, '无'),
  (2, 'practice', '以下关于三种性格类型话术的共同特点，描述正确的是？', '["都强调孩子的缺点需要改正","都先肯定孩子的特质，再说明课程如何正向引导","都建议家长改变孩子的性格","都承诺课程能改变孩子的性格"]', 1, '无'),
  (2, 'practice', '将''内向慢热''的话术转换为顾问可以学习的核心话术技巧，以下哪项最准确？', '["否定+承诺","接纳+渐进式引导+建立自信","批评+改正","忽视+等待"]', 1, '无'),
  (2, 'practice', '顾问在描述''急性子''孩子的应对话术时，重点应该放在什么上？', '["孩子的性格缺陷","课程如何帮助孩子培养细心、沉稳的习惯","让家长感到焦虑","强调课程难度"]', 1, '无'),
  (2, 'practice', '当孩子是第一次接触线上课程时，以下哪句预防针话术最恰当？', '["第一次上也没关系，我们老师都很有耐心，会一步步带着小朋友熟悉线上课堂，内容从简单有趣的开始，节奏轻松，不会给小朋友压力","第一次上线上课的孩子都会不适应","我们建议先上一对一课程适应","线上课需要孩子有很强的自制力"]', 1, '无'),
  (2, 'practice', '当孩子已经接触过线上课时，顾问应该如何回应？', '["那您应该试试我们的线下课程","那太好了，有过线上课经验孩子适应会更快，上课互动和配合度一般都会很不错，课堂效率也会更高","线上课效果不如线下课","之前的线上课可能不够好"]', 1, '无'),
  (2, 'practice', '将''第一次接触线上课''的话术转换为可学习的话术结构，以下哪项最准确？', '["恐吓+施压","消除顾虑+建立信任+说明课程设计+家长配合建议","贬低其他课程+抬高自己","直接跳过这个话题"]', 1, '无'),
  (2, 'practice', '在询问线上课程经验后，顾问还应该顺势了解什么？', '["之前课程的价格","家长为什么想让孩子体验线下（或线上）","之前课程的老师名字","孩子的线上课成绩"]', 1, '无'),
  (2, 'practice', '以下哪项不是''接触过线上课''话术中的关键要素？', '["表达喜悦和肯定","强调适应更快","指出之前课程的不足","强调课堂效率更高"]', 1, '无'),
  (2, 'practice', '顾问在打完''第一次接触线上课''的预防针后，建议家长做什么？', '["让孩子独自上课","爸爸妈妈可以一起鼓励小朋友去积极回答问题","不要打扰孩子上课","准备零食给孩子"]', 1, '无'),
  (2, 'practice', '对于幼儿阶段家长，以下哪句探询教育理念的话术最恰当？', '["您打算花多少钱给孩子报课？","妈咪，其实每个小朋友的状况都不太一样，想请问一下，您希望透过课程，优先帮孩子培养哪方面的能力呢？","您是不是觉得孩子比别人差？","您想让孩子考上名校吗？"]', 1, '无'),
  (2, 'practice', '国小阶段''痛点引导''的话术是什么？', '["很多国小孩子都是题目看得懂但不会写，您家小朋友主要是基础不稳，还是缺少解题方法呢？","您家孩子成绩怎么样？","您想让孩子考第几名？","您是不是觉得现在的老师教得不好？"]', 1, '无'),
  (2, 'practice', '将幼儿阶段教育理念探询话术转换为可学习的话术模板，以下哪项最准确？', '["直接质问型","个性化尊重+开放式需求引导+列举选项","恐吓焦虑型","封闭式是非题"]', 1, '无'),
  (2, 'practice', '国小阶段''开放式引导''的话术重点是什么？', '["直接给出课程方案","让家长自由表达最想达到的目标","强调课程价格优势","对比其他机构"]', 1, '无'),
  (2, 'practice', '当家长表示''想培养专注力''时，以下哪句回应最恰当？', '["专注力不重要，逻辑才重要","您真的抓到重点了！专注力确实是所有学习的基础。我们课堂互动非常密集，动画＋闯关式练习，全程抓住孩子注意力","专注力是天生的，培养不了","我们的课程不太注重专注力"]', 1, '无'),
  (2, 'practice', '当家长表示''想培养逻辑思维''时，顾问应该如何回应？', '["逻辑思维长大了自然就会","太对了！这个阶段正是逻辑思维黄金启蒙期。我们课程从分类、排序、规律、推理、空间概念这些底层能力入手，用可视化互动课件让思路变清楚","逻辑思维就是多做题","我们的课程主要教计算"]', 1, '无'),
  (2, 'practice', '当家长表示''希望孩子对数学有兴趣''时，以下哪项不是回应中的关键要素？', '["肯定家长方向正确","强调兴趣是长久学习的动力","说明课程的游戏化设计","承诺孩子一定会考上名校"]', 1, '无'),
  (2, 'practice', '当国小家长表示''成绩不太理想、基础弱''时，顾问的回应核心应该是什么？', '["批评孩子不够努力","先理解家长心情，再说明课程会先做能力定级，找到薄弱点，从对应级别开始补强","建议家长给孩子增加作业量","强调课程难度很大"]', 1, '无'),
  (2, 'practice', '当家长表示''应用题不会做、看不懂题目''时，以下哪句回应最能体现课程价值？', '["应用题就是多做题就会了","应用题核心就是逻辑理解。我们课程专门训练孩子拆解题目、抓关键信息、按步骤推理，用可视化方式把抽象题意变简单","应用题不重要，计算才重要","孩子理解力有问题"]', 1, '无'),
  (2, 'practice', '当家长表示''粗心、计算慢、容易错''时，顾问应该如何解释问题根源？', '["孩子太笨了","粗心其实是步骤感和专注力不足","孩子不够认真","题目太难了"]', 1, '无'),
  (2, 'practice', '当家长表示''想提升逻辑、独立思考能力''时，以下哪句回应最恰当？', '["逻辑思维很难培养","这个目标非常到位！国小正是思维定型关键期。我们不只教知识，更教思考方式：归纳、推理、举一反三、多角度思考","独立思考不重要，听话才重要","我们的课程主要是刷题"]', 1, '无'),
  (2, 'practice', '当家长表示''孩子没自信、害怕数学''时，顾问的回应策略应该是什么？', '["告诉孩子数学很简单","分析原因（因为不会才没兴趣）→ 说明课程从能胜任的级别开始→ 不断获得成就感→ 老师多鼓励引导→ 重建自信","批评孩子不够勇敢","建议家长多打骂孩子"]', 1, '无'),
  (2, 'practice', '将国小阶段''成绩不太理想、基础弱''的话术转换为可学习的话术结构，以下哪项最准确？', '["批评+施压+恐吓","共情理解+问题分析+解决方案+效果描绘","贬低+抬高+承诺","回避+转移话题"]', 1, '无'),
  (2, 'practice', '当出现决策人和约课人不一样时，顾问应该如何处理？', '["直接忽略，只跟约课人沟通","尽快打好预防针，建议妈妈邀请爸爸一起陪伴孩子去体验demo课，了解孩子的学习情况","要求决策人必须到场","告诉约课人不要告诉决策人"]', 1, '无'),
  (2, 'practice', '建议决策人一起参与demo课体验的主要目的是什么？', '["增加课程收入","让决策人了解孩子的学习情况，减少课后''和另一半商量''的阻力","展示课程给更多人看","满足公司KPI要求"]', 1, '无'),
  (2, 'practice', '将决策人处理话术转换为可学习的话术技巧，以下哪项最准确？', '["隐瞒+欺骗","提前预防+创造参与机会+情感联结（家庭氛围）","施压+逼迫","忽视+回避"]', 1, '无'),
  (2, 'practice', '在介绍''为什么学数学思维''时，以下哪项是VIP THINK强调的核心观点？', '["数学思维就是为了考试拿高分","高年级会出现思维能力的分水岭，3-6岁是逻辑思维发展的高速期，错过了黄金时间后面很难再锻炼","数学思维比语文更重要","学数学思维可以保送名校"]', 1, '无'),
  (2, 'practice', '将''为什么学数学思维''的话术转换为可学习的话术结构，以下哪项最准确？', '["恐吓+焦虑制造+逼迫","问题预警（分水岭）+ 原因分析（难度+思维需求）+ 对比（死记硬背vs逻辑思维）+ 时机强调（黄金期）+ 行动号召","贬低孩子+抬高课程","单纯介绍课程内容"]', 1, '无'),
  (2, 'practice', '顾问在介绍课程时提到''1-2年级学习成绩挺好，但3-4年级出现较大滑坡''，主要目的是什么？', '["批评低年级老师教得不好","制造问题意识，让家长意识到思维能力的重要性，从而产生紧迫感","吓唬家长","说明课程难度"]', 1, '无'),
  (2, 'practice', '文档中提到''以杜威/皮亚杰的教学理念为中心''，顾问在转述时应该强调什么？', '["强调两位教育家的学术地位","强调''和枯燥的教学不一样，让孩子在做中学，乐中学，帮助孩子发展认知思维''","详细讲解两位教育家的理论","让家长自己去查资料"]', 1, '无'),
  (2, 'practice', '预防针话术中，顾问应该如何定位这节体验课？', '["正式课程的第一节课","测评为主的体验课，让家长了解线上上课方式是否适合小朋友","免费赠送的课程","必须购买的课程"]', 1, '无'),
  (2, 'practice', '预防针话术中，顾问建议家长在课堂上做什么？', '["不要打扰孩子","在旁边多多鼓励她和老师进行互动，增强自信心，配合老师调动积极性","帮忙回答老师的问题","记录课堂内容"]', 1, '无'),
  (2, 'practice', '将预防针话术转换为可学习的话术技巧，以下哪项最准确？', '["恐吓+施压","降低期望+明确课程定位+家长参与建议+专业承诺（定级测评）","隐瞒+欺骗","直接推销"]', 1, '无'),
  (2, 'practice', '在确认上课时间时，顾问应该如何给出时间', '["问家长''您什么时候方便？''","给出具体的时间段选择，如''我们今晚7点20和8点10都是有开设试听课程''","让家长自己查课表","只给一个时间选项"]', 1, '无'),
  (2, 'practice', '在确认设备时，顾问的推荐逻辑是什么？', '["推荐最贵的设备","因为是小班互动课，推荐屏幕较大的设备（笔电或平板）","任何设备都可以","只推荐手机"]', 1, '无'),
  (2, 'practice', '如果在确认时间前忘记询问上课语言，顾问应该在什么时候补问？', '["不再询问","在给出时间段选择时补问","课后再问","让家长自己决定"]', 1, '无'),
  (2, 'practice', '加LINE时，顾问应该如何引导家长添加？', '["直接发送公司LINE ID让家长自己加","说明因为是官方账号加不了家长，请家长开扩音，顾问报ID，家长添加后发贴图或手机门号确认","不加LINE也可以","让家长发电话号码过来"]', 1, '无'),
  (3, 'practice', '知识点 【付款确认', '["直接去超商缴费","先注册成为AFTEE会员，点连结支付（选择先享后付），然后跳转到AFTEE完成第一笔缴费","先联系银行申请分期","先缴交全额保证金"]', 1, '根据SOP，分期支付第一步先注册成为AFTEE会员，之后就跟全款一样，让家长点连结支付（选择先享后付），然后跳转到AFTEE完成第一笔缴费。这是AFTEE分期的标准流程。  ──────────────────────────────────────────────────'),
  (3, 'practice', '话术 【付款确认', '["只能在线缴费。","妈咪，AFTEE支持两种缴费方式哦～您可以选择在线缴费，也可以去超商缴费，两种方式都很方便，看您哪种比较习惯！","去超商缴比较方便。","这个我不清楚，您自己查一下。"]', 1, '选项B完整说明了两种缴费方式（在线和超商），并给予家长选择权（看您哪种比较习惯），体现了以客户为中心的服务理念，同时语气亲切自然。  ──────────────────────────────────────────────────'),
  (3, 'practice', '知识点 【付款确认', '["直接安排上课","课表时间确认&信息采集","发送打卡规则","介绍转介绍活动"]', 1, '根据SOP流程顺序：一、付款确认 → 二、课表时间确认&信息采集 → 三、带入学步骤 → 四、带打卡 → 五、转介绍反馈方案。付款确认后应进入第二步。  ──────────────────────────────────────────────────'),
  (3, 'practice', '话术 【付款确认', '["钱付了，现在填资料。","非常感谢妈咪完成付款～为了帮小朋友顺利安排入学，接下来我们来确认一下课表时间，并请您填写一些入学资料哦！","付款完成了，你自己看着办吧。","付款确认了，等通知吧。"]', 1, '选项B先用『非常感谢』表达感谢，然后用『为了帮小朋友顺利安排入学』说明下一步的目的，让家长理解每个步骤都是为了孩子好，自然引导进入信息采集环节。  ──────────────────────────────────────────────────'),
  (3, 'practice', '话术 【课表时间确认&信息采集', '["你什么时候有空上课？","妈咪，这个是我们可以安排上课的时间，您可以选择两个比较合适上课的时间，我们会尽量配合您的时间来安排哦～","我们只有固定几个时间段，你选一个。","时间你自己定，告诉我就行。"]', 1, '选项B展示了可安排的时间选项，给予家长2个选择的弹性，并承诺『尽量配合您的时间』，体现了以客户为中心的服务态度，语气也亲切礼貌。  ──────────────────────────────────────────────────'),
  (3, 'practice', '话术 【带入学步骤', '["加一下我们的Line。","接下来我来带您入学～妈咪辛苦您添加一下我们官方lineID：排课老师@299ggeao（教务主要负责排课）、班导师@873hlxar（沟通上课情况和请假补课）、授课老师@031ztrhj（课前预习和课堂反馈），加入后传一下小朋友的学号哦！","有三个Line要加，你自己看着办。","Line账号发你了，加不加随便。"]', 1, '选项B用『接下来我来带您入学』自然过渡，清晰列出3个Line账号及其职责，并说明添加后的操作（传学号），让家长清楚每个账号的用途，避免混淆。  ──────────────────────────────────────────────────'),
  (3, 'practice', '知识点 【带入学步骤', '["负责排课","沟通上课情况，请假、补课和阶段情况反馈","负责课前预习","负责销售推广"]', 1, '根据SOP，班导师Line（@873hlxar）的职责是『沟通上课情况，请假、补课和阶段情况反馈』。这是家长日常沟通最频繁的窗口。  ──────────────────────────────────────────────────'),
  (3, 'practice', '话术 【带入学步骤', '["公司规定的，必须加。","妈咪，三个账号分工不同是为了让服务更专业高效～排课老师专门负责安排课程时间，班导师负责日常上课沟通和请假补课，授课老师则专注于课前预习和课后学情反馈，这样每个环节都有专人负责，能更好地服务小朋友哦！","加一个就够了，不用加这么多。","这个我也不清楚，你问别人吧。"]', 1, '选项B将『多个账号』转化为『专业高效』的优势，清晰说明每个账号的专业分工，强调最终受益者是『小朋友』，让家长理解这是为了提升服务质量，而非增加麻烦。  ──────────────────────────────────────────────────'),
  (3, 'practice', '知识点 【带打卡', '["仅能上课","兑换豌豆币课程、远程观看小朋友上课情况、打卡获得豌豆币","仅能打卡","仅能缴费"]', 1, '根据SOP：『【兑换豌豆币课程】，【远程观看小朋友上课情况】，【打卡获得豌豆币】，都在这个APP操作哦』。家长端是家长参与孩子学习过程的重要工具。  ──────────────────────────────────────────────────'),
  (3, 'practice', '话术 【带打卡', '["下载一下这个APP。","妈咪，这是家长端的下载方式，辛苦您可以下载一下唷～【兑换豌豆币课程 ，【远程观看小朋友上课情况 ，【打卡获得豌豆币 ，都在这个APP操作哦！","这个APP可有可无，下不下都行。","APP下载链接发你了。"]', 1, '选项B用『辛苦您可以下载一下唷～』礼貌请求，并用方括号强调三大核心功能（兑换课程、远程观课、打卡获币），让家长理解下载APP能带来的实际价值，提升下载意愿。  ──────────────────────────────────────────────────'),
  (3, 'practice', '知识点 【带打卡', '["24小时内","48小时内","72小时内","7天内"]', 1, '根据SOP：『您订单支付后的48小时内，完成第1次打卡』。第一次打卡有时间限制，顾问需要及时提醒家长在48小时内完成，错过将无法获得首次打卡奖励。  ──────────────────────────────────────────────────'),
  (3, 'practice', '话术 【带打卡', '["48小时内必须打卡，不然没奖励。","妈咪提醒您一下～订单支付后的48小时内完成第一次打卡，可以获得8000豌豆币（可以兑换1堂课）哦！时间比较紧迫，建议您尽快完成，我来教您怎么操作～","打卡随时都可以，不急。","48小时过了就不能打卡了。"]', 1, '选项B明确说明时间限制（48小时内）和奖励价值（8000豌豆币=1堂课），强调紧迫性但不制造焦虑，并主动提出协助（我来教您怎么操作），展现了积极的服务态度。  ──────────────────────────────────────────────────'),
  (3, 'practice', '知识点 【带打卡', '["2000豌豆币，可兑换0.25堂课","5000豌豆币，可兑换0.5堂课","8000豌豆币，可兑换1堂课","10000豌豆币，可兑换2堂课"]', 2, '根据SOP：『获得8000豌豆币（可以兑换1堂课）』。第一次打卡的奖励最丰厚，8000豌豆币可直接兑换1堂直播课，这是吸引家长尽快完成首次打卡的重要卖点。  ──────────────────────────────────────────────────'),
  (3, 'practice', '话术 【带打卡', '["打卡有奖励。","妈咪，第一次打卡可以获得8000豌豆币，直接可以兑换1堂免费直播课呢！这是给新入学小朋友的专属福利，非常划算哦～","打卡给点豌豆币，没什么用。","打卡奖励很少，不用太在意。"]', 1, '选项B将8000豌豆币转化为家长容易理解的价值（1堂免费直播课），强调这是『新入学小朋友的专属福利』，并用『非常划算』强化吸引力，激发家长行动意愿。  ──────────────────────────────────────────────────'),
  (3, 'practice', '知识点 【带打卡', '["8000豌豆币","5000豌豆币","2000豌豆币","1000豌豆币"]', 2, '根据SOP：『之后每次完成打卡...每次可获得2000豌豆币』。第一次打卡8000豌豆币是新手专属福利，后续每次打卡获得2000豌豆币，直到课时课包内课程消耗完为止。  ──────────────────────────────────────────────────'),
  (3, 'practice', '知识点 【带打卡', '["12小时","24小时","48小时","72小时"]', 1, '根据SOP：『【社交软件】上停留24小时后上传系统』。这是打卡审核的关键条件，分享必须在社交平台上保留24小时后再上传到家长端才算有效打卡。  ──────────────────────────────────────────────────'),
  (3, 'practice', '话术 【带打卡', '["打卡很简单，你自己弄。","分享的方式也比较简单～我们在家长端生成文案+附带链接，分享给facebook动态或者line，保存24小时，上传到家长端就算打卡成功了！","打卡很复杂，我建议你不要打。","打卡流程你自己看视频学。"]', 1, '选项B用『也比较简单』降低家长心理门槛，清晰列出操作步骤（生成文案+链接→分享到FB或Line→保存24小时→上传家长端），并明确成功标准，让家长对整个流程一目了然。  ──────────────────────────────────────────────────'),
  (3, 'practice', '知识点 【带打卡', '["5000豌豆币，家长端-我的-豌豆商城","8000豌豆币，家长端-首页-豌豆商城-热门兑换-豌豆益智直播课","10000豌豆币，家长端-设置-兑换中心","2000豌豆币，家长端-课程-兑换"]', 1, '根据SOP：『家长端-首页-豌豆商城-热门兑换-豌豆益智直播课-8000豌豆币兑换一堂直播课』。兑换路径较长，顾问需要熟悉并能准确指导家长操作。  ──────────────────────────────────────────────────'),
  (3, 'practice', '话术 【带打卡', '["在APP里找一下就能兑换。","妈咪，兑换路径是：打开家长端→首页→豌豆商城→热门兑换→豌豆益智直播课→用8000豌豆币兑换一堂课。我这边也有操作图片/视频可以参考，需要我发给您吗？","兑换很简单，不用教。","你自己摸索一下。"]', 1, '选项B用箭头符号清晰展示兑换路径的每一步，让家长可以按图索骥操作，并主动提供额外帮助（操作图片/视频），展现了细致周到的服务态度。  ──────────────────────────────────────────────────'),
  (3, 'practice', '知识点 【转介绍反馈方案', '["现金红包","额外加送3堂直播课","豌豆币10000个","课程折扣券"]', 1, '根据SOP：『您的小孩就能额外加送3堂课』。转介绍的核心奖励是3堂免费直播课，这是对现有学员的直接课程反馈，价值明确且吸引力强。  ──────────────────────────────────────────────────'),
  (3, 'practice', '知识点 【转介绍反馈方案', '["仅需提供手机门号","成功出席体验课并完成上课","仅需注册账号","仅需支付订金"]', 1, '根据SOP：『亲友成功出席体验课并完成上课』。转介绍奖励的发放条件是亲友不仅要出席体验课，还要完成整堂课的上课，确保推荐质量。  ──────────────────────────────────────────────────'),
  (3, 'practice', '话术 【转介绍反馈方案', '["让你朋友来报名就行。","流程很简单妈咪～第一步：提供亲友手机门号（家里有适龄孩子）；第二步：亲友成功出席体验课并完成上课；第三步：您的小孩就能额外加送3堂课！推荐越多送越多哦～","流程很复杂，我建议你不要参加。","具体流程我也不太清楚。"]', 1, '选项B用『流程很简单』降低心理门槛，分三步清晰说明（提供门号→亲友完成体验课→获得3堂课），并用『推荐越多送越多』激励家长多推荐，结构清晰且具吸引力。  ──────────────────────────────────────────────────'),
  (3, 'practice', '知识点 【转介绍反馈方案', '["仅推荐人获得好处","亲友孩子能免费体验优质数学思维课，推荐人小孩的课堂数直接增加","仅被推荐人获得好处","顾问获得业绩提成"]', 1, '根据SOP：『双重好处：亲友孩子能免费体验优质数学思维课；您家小孩的课堂数直接增加，推荐越多送越多！』。这是一个双赢的活动设计，既让被推荐人受益，也让推荐人获得实质反馈。  ──────────────────────────────────────────────────'),
  (3, 'practice', '课后跟进四步法的第一步是什么？', '["讲解测评报告","询问上课感受","产品介绍","方案推荐与关单"]', 1, '课后跟进四步法依次为：第一步询问上课感受、第二步讲解测评报告、第三步产品介绍、第四步方案推荐与关单。第一步的核心要求是及时联系（体验课结束后尽快沟通，1次未接通则30分钟内再次跟进）和了解感受（主动询问家长对课堂的评价，重点记录''满意环节''和''待改善点''）。'),
  (3, 'practice', '体验课结束后，若首次联系家长未接通，应在多久内再次跟进？', '["10分钟内","30分钟内","1小时内","2小时内"]', 1, '根据SOP要求，体验课结束后应尽快沟通，1次未接通则30分钟内再次跟进，目的是趁课堂记忆清晰时推进沟通，提高跟进效率。'),
  (3, 'practice', '当家长反馈孩子''觉得难''时，以下哪句话术最恰当？', '["「没关系，我们的课程本来就比较难，孩子需要多练习。」","「没关系~体验课是测试孩子思维能力，不是单纯教知识。您有没有发现XX一开始有点紧张，但后来慢慢跟上节奏了？这种新模式需要适应，正式课会先做定级测评，再用6E教学法循序渐进引导，孩子很快就能适应~」","「觉得难是正常的，其他小朋友一开始也觉得难。」","「那我们先不学这个了，等孩子大一点再说。」"]', 1, '当家长反馈''觉得难''时，正确话术应：1）安抚家长情绪；2）说明体验课的定位是测试而非教学；3）引导家长关注孩子的适应过程；4）说明正式课有定级测评和6E教学法循序渐进引导。选项B完整涵盖了这些要点，能有效消除家长顾虑。'),
  (3, 'practice', '讲解测评报告时，优点与不足的比例应如何呈现？', '["1:1","2:1","3:1或3:2","4:1"]', 2, '讲解测评报告时，应按3:1或3:2的比例呈现优缺点，突出3个优点（如专注力好、主动探索、快速吸收），搭配1-2个轻微不足（如逆向推理稍慢、受视觉干扰）。这样的比例既能增强家长信心，又能自然引导到正式课的解决方案。'),
  (3, 'practice', '讲解测评报告的5要素不包括以下哪一项？', '["体验课的收获是什么","升学和课程的关联性","孩子在课堂的表现亮点及提升地方","家长的职业背景"]', 3, '讲解测评报告的5要素包括：1）体验课的收获是什么；2）升学和课程的关联性要输出给家长；3）孩子在课堂的表现亮点以及提升的地方；4）老师的建议、评价；5）引导正式课的讲解。家长的职业背景不属于5要素内容。'),
  (3, 'practice', '产品介绍的讲解原则遵循什么公式？', '["需求→方案→价格→成交","上什么→怎么上→达成效果→如何保障","痛点→产品→优惠→关单","介绍→体验→反馈→报名"]', 1, '产品介绍的讲解原则是结合孩子特点和家长需求，突出课程有效性，遵循''上什么→怎么上→达成效果→如何保障''的公式，逻辑清晰地让家长理解课程价值。'),
  (3, 'practice', 'VIPThink课程体系参照什么标准设计？', '["中国教育部课程标准","美国NCTM（数学教师协会）标准","英国国家课程标准","新加坡数学课程标准"]', 1, 'VIPThink课程体系参照美国NCTM（数学教师协会）标准设计，该标准是全球最大数学教育组织制定的，对不同年龄段孩子该掌握的数学知识、思维能力有严谨要求，广泛应用于美国顶尖中小学。'),
  (3, 'practice', '6E教学法中，''拓展''环节的核心内容是什么？', '["用动画情境吸引兴趣","提趣味问题引导孩子主动思考","多元场景应用，练实用性思维","师生双向反馈，同步学习进度"]', 2, '6E教学法六个环节分别为：导入（用动画情境吸引兴趣）、探索（提趣味问题引导思考）、解释（用游戏课件解决理解偏差）、拓展（多元场景应用，练实用性思维）、表达（鼓励孩子梳理思路外化思维）、评估（师生双向反馈同步进度）。拓展环节强调将知识应用到不同生活场景中。'),
  (3, 'practice', '学习闭环流程的正确顺序是？', '["课前预习→课堂互动→课后复习→效果检测","效果检测→课前预习→课堂互动→课后复习","课堂互动→课前预习→课后复习→效果检测","课前预习→效果检测→课堂互动→课后复习"]', 0, '学习闭环流程为：课前预习（动画预热）→课堂互动（解题思路可视化）→课后复习（线上练习+线下拓展教材）→效果检测（定级测评、专题探索、阶段总结）。这个闭环确保孩子学得扎实，家长能清楚了解学习进度。'),
  (3, 'practice', '''1V3''专属学习陪伴中，班导老师的主要职责是什么？', '["首次排课","请假/调课","解答课堂疑问","销售课程"]', 1, '''1V3''专属学习陪伴包括：课程顾问（衔接沟通）、班导老师（请假/调课）、授课老师（答疑）。教务老师负责首次排课。班导老师主要负责学员的日常课程安排调整。'),
  (3, 'practice', '全年包（90课时）的优惠后价格是多少？', '["25,000台币","41,500台币","68,000台币","35,000台币"]', 1, '三个课包价格分别为：半年包（53课时）25,000台币、全年包（90课时）41,500台币、两年包（165课时）68,000台币。全年包是最受台湾家长欢迎的方案，兼顾培养连贯性和CP值。'),
  (3, 'practice', '推荐方案时，前期铺垫话术的核心目的是什么？', '["直接告诉家长价格","排雷+异议前置，确认家长无产品疑问后再推进","立即发送付款链接","强调优惠力度"]', 1, '前期铺垫话术的核心是''排雷+异议前置''，先确认家长对课程学习方法和内容没有不清楚的地方，再引导确定上课时间、预留班级和老师。这样可以提前发现并解决潜在异议，提高关单成功率。'),
  (3, 'practice', '优惠释放的正确顺序是？', '["转介绍赠课→打卡赠课→试听赠课+粉丝福利","试听赠课+粉丝福利→打卡赠课→转介绍赠课","打卡赠课→试听赠课+粉丝福利→转介绍赠课","试听赠课+粉丝福利→转介绍赠课→打卡赠课"]', 1, '优惠释放应分三轮：第一轮（基础优惠）试听赠课+粉丝福利、第二轮（附加优惠）打卡赠课、第三轮（长期优惠）转介绍赠课。分轮释放的目的是不一次性给完所有优惠，保留后续沟通筹码，同时逐步增加吸引力。'),
  (3, 'practice', '渲染优惠时，以下哪项不是核心要求？', '["客户对产品无异议后再释放优惠","分轮释放优惠，不一次性给完","突出优惠的稀缺性和价值感","在介绍产品初期就释放所有优惠"]', 3, '渲染优惠的三大核心要求是：1）客户对产品无异议后再释放优惠，加快成交；2）分轮释放优惠，不一次性给完，保留后续沟通筹码；3）突出优惠的稀缺性（如''仅限体验当天''）和价值感（如''赠课能学3个月''）。在产品初期就释放所有优惠是错误的，会失去谈判筹码。'),
  (3, 'practice', '关单说服的整体思路围绕哪''三性''展开？', '["重要性、紧迫性、有效性","经济性、实用性、便捷性","专业性、权威性、系统性","趣味性、互动性、灵活性"]', 0, '关单说服的整体思路围绕''重要性（为什么要学）、紧迫性（为什么现在学）、有效性（为什么选我们）''多轮说服，消除家长顾虑。这是处理所有异议的底层逻辑框架。'),
  (3, 'practice', '当家长说''我再考虑下，有需要联系你''时，以下哪句回应最恰当？', '["「好的，那您考虑好了再联系我。」","「没问题，XX妈妈！您是不是有具体担心的点呀？其实您核心顾虑无非三点：要不要学、现在学还是以后学、选我们还是其他机构...」","「我们的优惠今天就结束了，您现在不报名就亏了。」","「很多家长都说考虑，最后都没报名，您还是现在决定吧。」"]', 1, '面对''再考虑''的异议，正确做法是：1）先询问具体顾虑点；2）围绕''三性''（重要性、紧迫性、有效性）进行说服；3）提供学习案例增强说服力。选项B体现了这一思路，既尊重家长又主动引导。直接放弃（A）、单纯施压（C/D）都不是最佳策略。'),
  (3, 'practice', '当家长说''需要和家人商量''时，顾问应首先做什么？', '["立即结束对话，等家长商量完再联系","询问主要和谁商量，主动提出和决策人沟通","告诉家长优惠马上结束，不能等","直接发送付款链接给家长"]', 1, '面对''需要商量''的异议，正确思路是：1）判断是否是真异议；2）询问和谁商量、商量什么；3）表示理解，重申思维提升的重要性、紧迫性和有效性；4）顾问主动提出和决策人沟通；5）约好具体时间做下次跟进。选项B符合这一流程。'),
  (3, 'practice', '退费保障承诺中，''4堂无忧试学''的具体内容是？', '["报名后前4堂课内，任何问题都可以全额退费","报名后前4堂课内，只能退50%费用","报名后前4堂课内，不能退费","报名后前4堂课内，需要扣除手续费才能退费"]', 0, '退费保障承诺包括：1）4堂无忧试学——报名后前4堂课内，任何问题都可以全额退费，零风险体验；2）超过4堂也能随时退——只需扣除已上课时费用，剩余金额全数退还；3）零手续费——无论哪种退费方式，都不收任何手续费，原路退回。'),
  (3, 'practice', '当家长说''价格太贵了''时，以下哪项不是正确的处理思路？', '["分散家长对于总价的注意力，强调单节课价格","强调课程内容带来的价值","直接降价以促成交易","将学习定义为投资而非消费"]', 2, '处理''价格贵''异议的正确思路包括：1）分散对总价的注意力，强调单节课才三百台币；2）强调课程内容价值（6E教学法、小班制、双师服务等）；3）明确学习困难和学习目标；4）将学习定义为投资而非消费。直接降价会破坏价格体系，不是正确的处理方式。'),
  (3, 'practice', '两年包（165课时）最多可获得多少堂课？', '["165堂","190堂","222堂","200堂"]', 2, '两年包包含165堂正式课+29堂试听赠课+4堂粉丝福利+24堂打卡赠课，最多共222堂。这是三个方案中CP值最高的，课时足够覆盖孩子1-2年系统思维训练。'),
  (3, 'practice', '异议处理中，''有同理心''的具体表现是什么？', '["直接反驳家长的观点","让客户认识到你同样是站在他的角度看问题","强调产品的绝对优势","尽快结束对话"]', 1, '成功处理异议的七要素之一是''有同理心''，即让客户认识到你同样是站在他的角度看问题，之后再处理事情会事半功倍。常用句式如''我非常理解...''。直接反驳（A）会破坏信任关系。'),
  (3, 'practice', '异议处理中，''集中火力''的含义是？', '["逐个解决每个异议，不遗漏","关单环节产生的异议要一起集中解决","只关注最重要的一个异议","让家长自己解决异议"]', 1, '''集中火力''指关单环节产生的异议要一起集中解决，常用话术如''理解理解，还有别的顾虑吗？''或''除了...，还有其他方面的担心吗？''目的是一次性解决所有顾虑，避免反复拉锯。'),
  (3, 'practice', '当家长说''孩子现在还小，等大一点再学吧''，若家长是担心孩子看不懂、学不会，以下哪句话术最恰当？', '["「那我们就等孩子大一点再联系您。」","「您放心，我们教授的内容是该年龄段孩子能够掌握的。我们采用从具象到半具象再到抽象的教学法，让孩子明白为什么这么做，而不只是报答案。」","「其他小朋友都能学会，您的孩子一定也可以。」","「现在不学就来不及了，别的孩子都在学。」"]', 1, '针对''怕孩子看不懂''的顾虑，正确话术应：1）说明教材按美国NCTM标准编写，是该年龄段能掌握的内容；2）强调采用皮亚杰理论中的从具象到半具象再到抽象的教学法；3）举例说明如何教孩子理解加法意义，而非死记硬背。选项B专业且有说服力。'),
  (3, 'practice', '当家长说''担心孩子坚持不下来''，若原因是''对数学不感兴趣''，以下哪句回应最恰当？', '["「数学本来就比较枯燥，孩子不感兴趣很正常。」","「这个您完全不需要担心。VIPThink提倡快乐学习，以游戏化教学激发兴趣，超级飞侠IP人物会陪着孩子一起思考、探索、解决问题，好多小朋友课程结束了都不肯下线。」","「那我们先不报，等孩子感兴趣再说。」","「您要多督促孩子，培养他的兴趣。」"]', 1, '针对''不感兴趣''的顾虑，应强调：1）VIPThink不是一味做题套公式，而是快乐学习；2）游戏化教学设计；3）超级飞侠等IP人物的吸引力；4）实际案例（小朋友不肯下线）。选项B完整涵盖了这些要点。'),
  (3, 'practice', '当家长说''电子设备对眼睛不好，怕对视力有影响''，以下哪项不是正确的应对思路？', '["表示理解家长的担心","说明每次连续用眼30-60分钟在安全范围","强调一周才两节课，用眼时间完全在安全范围","告诉家长完全不用担心，电子产品对眼睛没有任何影响"]', 3, '正确应对思路是：1）表示理解；2）说明影响视力的关键是连续用眼时长，30-60分钟在安全范围；3）强调一周仅两节课，总用眼时间很少；4）引导家长关注思维启蒙的长期价值。说''没有任何影响''（D）不科学，会降低可信度。'),
  (3, 'practice', '当家长说''喜欢1对1的，人多没效果''时，以下哪项不是推荐小班制的理由？', '["小班制能实现''精准关注+高效吸收''的平衡","小班制能激发孩子的主动学习动力","小班制比1对1更便宜","小班制兼顾''知识学习+综合能力培养''"]', 2, '推荐小班制的三大理由：1）精准关注+高效吸收（老师能精准掌握每位孩子进度）；2）激发主动学习动力（同伴竞争互助激发表达欲和求知欲）；3）兼顾知识学习与综合能力培养（社交、表达、规则意识）。价格更便宜不是推荐小班制的核心理由，且文档中未提及此点。'),
  (3, 'practice', '当家长说''想要一周一节''时，顾问应如何回应？', '["「好的，我们可以安排一周一节。」","「我们这个课程是一周两次课，而且是固定的。2016年我们做过约5000个学员的长期追踪，发现一周两次课的效果是最好的，之后就统一安排成一周两次课了。」","「一周一节也可以，但效果会差一点。」","「一周一节的话价格可以便宜一些。」"]', 1, '正确回应应：1）明确说明课程固定为一周两次；2）用数据支撑（约5000学员长期追踪）；3）强调核心诉求是让孩子学有所得；4）说明上课时间灵活可选。选项B专业且有说服力，直接答应（A）或模糊回应（C）都不符合SOP。'),
  (3, 'practice', '当家长说''网上说你们不好''时，以下哪句回应最恰当？', '["「网上的评价都是假的，不要相信。」","「哦，原来是这样啊，那你看到我们哪些不好的内容呢？像我们是环球企业，树大自然容易招风。好与不好，您亲眼看到、能够保证兑现给您的，才是事实。」","「那些都是竞争对手恶意诋毁，不用理会。」","「我们的口碑一直很好，网上说的不是真的。」"]', 1, '正确应对思路：1）了解具体不好的内容点；2）树大招风，让家长知道眼见才为实；3）突出VIPThink亮点增强信心。选项B既了解具体情况，又引导家长关注自身体验，是最专业的回应。直接否定（A/C/D）会显得防御性强、缺乏说服力。'),
  (3, 'practice', '当家长选择线下课时，以下哪项不是线上课的优势？', '["不用奔波赶路，在家就能上课","同基础6-8人小班，能了解同学思路","家长可旁听、可回放，更透明","线下课老师能亲自照看孩子，更有情感连结"]', 3, '线上课的优势包括：1）不用奔波，节省时间；2）同基础小班，开阔视野锻炼表达；3）家长可旁听回放，透明安全；4）老师对孩子了解更细更快；5）顾问持续追踪进步轨迹。选项D是线下课的特点，不是线上课的优势。'),
  (3, 'practice', '成功处理异议的七要素中，''趁热打铁''指的是？', '["处理完所有异议后，立即关单","在家长情绪激动时快速成交","不断给家长施压","等家长冷静后再联系"]', 0, '''趁热打铁''指处理完所有异议后，要立马关单，抓住家长顾虑消除后的最佳成交时机。异议处理过程基本不可能一遍过，需要坚持三轮以上，但每轮解决后都应及时推进关单。'),
  (3, 'practice', '当家长说''我想买个短期的试试''，推长期方案时，以下哪项不是正确的说服点？', '["学习需要坚持，短期体验顶多让孩子摸个皮毛","长期报名更省心，不用频繁换课适应新老师","长期学员有专属学情追踪服务","短期课程质量比长期课程差"]', 3, '推长期方案的正确说服点：1）学习需要坚持，短期难扎实；2）长期更省心，不用频繁适应；3）有专属学情追踪；4）前4堂无忧试学保障。说''短期课程质量差''（D）会贬低产品，且与事实不符（文档强调短期也能感受乐趣和初步效果）。'),
  (3, 'practice', '当家长说''如何保证学习效果''时，以下哪项不属于服务体系的内容？', '["课前预习、课堂学习、课后功课和课后复习的闭环模式","授课老师及时把课堂表现以文字形式反馈到Line","定期提供课堂内容总结、学习报告和家长手册","每天安排家长到校面谈"]', 3, '保证学习效果的服务体系包括：1）闭环学习模式（课前预习、课堂学习、课后功课、课后复习）；2）3+1学习跟进（顾问+授课老师+班导老师）；3）授课老师及时文字反馈课堂表现到Line；4）定期课堂总结、学习报告、家长手册。每天到校面谈（D）不是线上教育的服务方式。'),
  (3, 'practice', '当家长说''担心效果不好/怕孩子不适合''时，以下哪句话术最能降低决策门槛？', '["「我们的课程效果很好，您不用担心。」","「妈咪完全理解您的担心！我们特别设计了4堂无忧试学，报名后前4堂课任何问题都可以全额退费，零风险体验。」","「其他小朋友都适应得很好，您的孩子也一定可以。」","「如果您现在不报名，以后就没有这个优惠了。」"]', 1, '针对''担心效果''的异议，最有效的话术是强调退费保障——4堂无忧试学，前4堂课内任何问题全额退费。这直接将家长的决策风险降为零，是最有力的临门一脚。空口承诺（A/C）或施压（D）效果都不如具体的保障机制。'),
  (3, 'practice', '当家长说''退费流程复杂/担心退不到钱''时，以下哪项不是退费承诺的内容？', '["4堂内全额退，原路全数退回","超过4堂按比例退，计算透明","需要扣除20%手续费","通常7-14个工作日到账"]', 2, '退费承诺明确包括：1）4堂内全额退；2）超过4堂按比例退；3）零手续费；4）原路退回；5）7-14个工作日到账。''扣除20%手续费''（C）与''零手续费''承诺直接矛盾。'),
  (3, 'practice', '当家长说''孩子现在还小，等大一点再学吧''，若家长认为没必要现在学，以下哪项不是正确的说服点？', '["3-6岁是大脑快速发育阶段，神经元达到顶峰","小班学起能打下坚实基础，培养逻辑思维和独立思考能力","大班再学时间紧，很多知识可能一知半解、死记硬背","现在报名可以享受最大优惠力度"]', 3, '针对''认为没必要现在学''的正确说服点：1）3-6岁大脑发育黄金期；2）小班学起的好处（玩中学、动手操作、勇敢表达）；3）大班再学的弊端（时间紧、应试导向、死记硬背）。用优惠力度（D）说服不符合''重要性-紧迫性-有效性''的异议处理框架，且显得功利。'),
  (3, 'practice', '签单后，家长全款支付后需要回传什么？', '["孩子的成绩单","付款成功的截图（台币）","身份证复印件","课程评价"]', 1, '签单后付款确认步骤：全款支付时，请家长回传付款成功的截图（台币），方便做入学登记。分期支付则需确认用户完成第一笔缴费，才算分期成功。'),
  (3, 'practice', '签单后信息采集需要家长填写的内容不包括？', '["孩子英文名、中文名、出生年月日","孩子性格、喜欢的老师类型","家长的年收入","平时上课时间段、想提升的地方"]', 2, '信息采集内容包括：孩子英文名、中文名、出生年月日、现在年级、城市、孩子性格、喜欢什么类型的老师、上课中对老师有什么要求、平时上课时间段、想提升的地方、希望顾问电话服务的时间段、妈妈的LineID。家长的年收入不属于信息采集范围。'),
  (3, 'practice', '签单后，家长需要添加哪三个Line账号？', '["课程顾问、销售经理、客服","排课老师、班导师、授课老师","校长、班主任、学科组长","财务、教务、客服"]', 1, '签单后需要家长添加三个Line账号：1）排课老师（@299ggeao，教务主要负责排课）；2）班导师（@873hlxar，沟通上课情况、请假补课和阶段情况回馈）；3）授课老师（@031ztrhj，负责课前预习和课堂学情回馈）。'),
  (3, 'practice', '打卡规则中，首次打卡需要在什么时间完成？', '["购课后24小时内","购课后48小时内","购课后72小时内","购课后一周内"]', 1, '打卡规则：购课的48小时内完成首次打卡，直接赠送8000豌豆币。后期是一周打一次，打一次送2000豌豆币。8000豌豆币可兑换1堂正式课。'),
  (3, 'practice', '打卡分享需要在社交软件上停留多久后上传系统？', '["12小时","24小时","48小时","72小时"]', 1, '打卡规则：分享海报到社交软件（Facebook或Line）后，需要停留24小时后上传系统，才算打卡成功。首次打卡获8000豌豆币，后续每次打卡获2000豌豆币。'),
  (3, 'practice', '转介绍回馈方案中，推荐好友成功出席体验课并完成上课，可获得多少堂赠课？', '["1堂","2堂","3堂","5堂"]', 2, '转介绍回馈方案：提供亲友手机号（家里有适龄孩子）→亲友成功出席体验课并完成上课→您的小孩就能额外加送3堂直播课。推荐越多送越多。'),
  (3, 'practice', '豌豆币兑换1堂正式课需要多少积分？', '["2000豌豆币","5000豌豆币","8000豌豆币","10000豌豆币"]', 2, '8000豌豆币=1堂正式课。兑换路径：家长端-首页-豌豆商城-热门兑换-豌豆益智直播课-8000积分兑换。首次打卡直接送8000豌豆币（等于1堂课），后续每次打卡送2000豌豆币。'),
  (3, 'practice', '话术速查表中，''课纲衔接''场景的核心话术是什么？', '["「70%衔接108课纲，30%锻炼思维逻辑」","「我们的课程完全按照108课纲设计」","「我们的课程比108课纲更难」","「108课纲不重要，我们的方法更好」"]', 0, '话术速查表中''课纲衔接''的核心话术是''70%衔接108课纲，30%锻炼思维逻辑''，目的是让家长感觉课程符合本地教育需求，同时又有额外的思维训练价值。'),
  (3, 'practice', '话术速查表中，''价格化解''场景的核心话术是什么？', '["「我们的价格是最便宜的。」","「单堂300元，外面补习班要四五百」","「价格不重要，效果才重要。」","「我们可以给您打五折。」"]', 1, '话术速查表中''价格化解''的核心话术是''单堂300元，外面补习班要四五百''，通过对比重塑性价比认知，让家长觉得VIPThink不仅不贵，反而更划算。'),
  (3, 'practice', '话术速查表中，''黄金期紧迫''场景的目的是？', '["让家长觉得课程很紧急，必须马上买","制造紧迫感，让家长意识到3-12岁是思维培养黄金期，错过要花数倍力气重建","吓唬家长，说孩子不学会落后","强调课程时间有限"]', 1, '话术速查表中''黄金期紧迫''的核心话术是''3-12岁是黄金期，错过要花数倍力气重建''，目的是科学合理地制造紧迫感，让家长意识到思维培养有关键期，而非单纯施压。'),
  (3, 'practice', '以下哪句话术对应''建立信任''场景？', '["「用大屏幕设备上课效果会好一些」","「老师专门负责台湾学员，班级专为台湾学生量身打造」","「40分钟线上课程，真人老师实时互动，游戏化闯关形式」","「培养带得走的能力，适应未来生活」"]', 1, '话术速查表中各场景对应：A是''设备准备''、B是''建立信任''（消除地域顾虑）、C是''课堂形式''、D是''长期价值''。''老师专门负责台湾学员，班级专为台湾学生量身打造''能有效消除台湾家长对跨境服务的顾虑。'),
  (3, 'practice', '使用提示中，''分轮释放优惠''的目的是？', '["让家长觉得优惠很多","不要一次性给完所有优惠，保留谈判筹码","快速成交","显示顾问的权力"]', 1, '使用提示明确说明：''分轮释放优惠：不要一次性给完所有优惠，保留谈判筹码''。这是销售谈判的重要技巧，逐步释放优惠可以持续吸引家长，并在关键时刻作为推进成交的工具。'),
  (3, 'practice', '当家长反馈''还可以''时，顾问应如何引导？', '["「那您就报名吧，课程很好的。」","「那您觉得课堂里哪个部分让您印象最深刻呀？是动画情境，还是互动游戏环节呢？」","「只是还可以吗？您是不是不满意？」","「其他家长都说很好，您为什么觉得还可以？」"]', 1, '当家长说''还可以''时，说明反馈较为平淡，顾问需要主动引导家长表达真实想法。正确话术是追问具体印象最深刻的部分（动画情境或互动游戏环节），通过具体化问题挖掘家长的真实感受，为后续沟通铺垫。'),
  (3, 'practice', '产品介绍的''达成效果''包括哪四个维度？', '["兴趣与探索、思维习惯、应用能力、基础积累","计算能力、记忆力、专注力、表达能力","课前预习、课堂互动、课后复习、效果检测","导入、探索、解释、拓展"]', 0, '达成效果的四个维度是：1）兴趣与探索（寓教于乐，建立成就感）；2）思维习惯（多角度观察、有条理分析）；3）应用能力（知识迁移、举一反三）；4）基础积累（掌握核心数学知识点）。选项C是学习闭环的环节，选项D是6E教学法的部分环节。'),
  (3, 'practice', '以下哪项是''6E教学法''的正确顺序？', '["导入→探索→解释→拓展→表达→评估","导入→解释→探索→拓展→评估→表达","探索→导入→解释→拓展→表达→评估","导入→探索→拓展→解释→表达→评估"]', 0, '6E教学法的正确顺序是：导入（Engage）→探索（Explore）→解释（Explain）→拓展（Extend/Elaborate）→表达（Express）→评估（Evaluate）。这是国际广受认可的教学法，每个环节都有明确的功能定位。'),
  (4, 'practice', '体验课结束后，课程顾问需要给家长提供什么来展示孩子的学习情况？', '["仅口头描述孩子上课表现","授课老师反馈的专属学习评估报告，包含知识点掌握、互动积极性、思维方式特点、优势与待提升处","一份标准化的通用报告模板，所有孩子内容相同","只发送课堂录像让家长自行判断"]', 1, '体验课结束后顾问需致电讲解授课老师反馈的『小朋友专属学习评估报告』，内容包括知识点掌握情况、课堂互动积极性、思维方式特点、优势和需要提升的地方，并给出针对性学习建议。这是建立专业信任、推动转化的关键工具。'),
  (4, 'practice', '家长问：『上完体验课，孩子能学到什么具体的东西？』以下哪种话术最能体现价值感？', '["『就是体验一下上课形式，学不到什么具体内容的。』","『这堂课围绕XX思维方法设计，孩子能初步掌握这个方法，学会解决1-2个实际数学问题，同时充分体验线上互动模式，激发学习兴趣。』","『体验课内容很简单的，主要是让孩子玩一玩。』","『具体学什么要看老师安排，我也不确定。』"]', 1, '体验课围绕具体思维方法（如图形分类、逻辑推理、数感启蒙）设计，孩子能『初步掌握这个具体的思维方法，还能学会用这个方法解决1-2个实际的数学问题』，同时体验上课形式、激发兴趣。这种回答既具体又有价值感，避免让家长觉得体验课『只是玩玩』。'),
  (4, 'practice', 'VIPTHINK数学思维课与学校数学补习班的核心区别是什么？', '["VIPTHINK课程更难，适合超前学习","补习班侧重课本知识巩固和习题反复练习；VIPTHINK侧重逻辑思维、问题解决、创新思考等能力培养，不是单纯补习题","VIPTHINK只教计算技巧，补习班教应用题","两者没有区别，都是提升数学成绩"]', 1, '学校补习班主要侧重课本知识巩固、习题反复练习，目的是提升应试成绩；而VIPTHINK核心是培养逻辑思维、问题解决、创新思考等能力。举例：同样是学加法，补习班让孩子反复做计算题，而VIPTHINK让孩子理解加法意义，学会解决生活中的实际问题，培养举一反三的思维能力。'),
  (4, 'practice', '家长说：『这不就是补习数学吗？跟学校补习班有什么不一样？』顾问应如何回应？', '["『对啊，就是补习数学，但我们的老师更好。』","『两者的核心区别很大哦！补习班侧重课本知识巩固和刷题，目的是提升应试成绩；我们侧重培养逻辑思维、问题解决能力。比如学加法，补习班让孩子反复做10+5、8+7，我们让孩子理解加法意义，学会解决生活中的实际问题，培养举一反三的能力。长期下来不仅数学成绩提升，其他学科也会受益。』","『我们比补习班便宜，所以更划算。』","『其实差不多，主要看孩子喜欢哪个老师。』"]', 1, '先明确核心区别（补习班侧重知识巩固刷题 vs 思维课侧重能力培养），再用具体例子（加法的学习方式对比）说明差异，最后强调长期价值（不仅数学成绩提升，其他学科也受益）。这种『对比+举例+升华』的结构最具说服力。'),
  (4, 'practice', '长期学习VIPTHINK课程，除了数学成绩提升，还能培养孩子哪些能力？', '["仅提升计算速度","专注力、表达能力、创新能力、规则意识和社交能力","仅提升考试技巧","仅提升绘画能力"]', 1, '长期学习能培养『专注力、表达能力、创新能力、规则意识和社交能力』，这些能力会让孩子受益一辈子。顾问在回答时要强调『根源培养』——让孩子学会理解题意、找解题思路、灵活运用方法，而不是死记硬背公式刷题。'),
  (4, 'practice', '家长问：『长期学下来，对孩子的数学成绩提升帮助大吗？』顾问的最佳回应应包含哪些要素？', '["『帮助很大，保证孩子考100分。』","『帮助很明显！因为我们从根源上培养数学思维能力，让孩子学会理解题意、找解题思路、灵活运用方法。通过自评题精准匹配阶段和老师，孩子循序渐进提升，面对学校基础题和难题都能快速找到方法，成绩自然稳步提升。』","『成绩提升要看孩子自己努力，我们没办法保证。』","『只要上课认真听，成绩肯定能提高。』"]', 1, '① 肯定回答（帮助很明显）；② 解释原因（从根源培养思维能力，而非死记硬背）；③ 具体说明（理解题意→找思路→灵活运用）；④ 机制保障（自评题精准匹配阶段和老师，循序渐进）；⑤ 结果呈现（面对基础题和难题都能快速找到方法，成绩稳步提升）。避免过度承诺（如『保证100分』），也避免推卸责任（如『看孩子自己努力』）。'),
  (4, 'practice', '体验课围绕什么目标设计？以下哪项描述最准确？', '["让孩子掌握一学期的数学知识","让孩子体验上课形式、互动模式，初步掌握一个具体思维方法，激发学习兴趣","进行正式课的入学考试","让家长了解课程价格"]', 1, '体验课目标：① 让孩子体验上课形式、互动模式；② 初步掌握一个具体思维方法（如图形分类、逻辑推理、数感启蒙）；③ 学会用该方法解决1-2个实际问题；④ 激发学习兴趣；⑤ 为后续正式课前的自评题和精准匹配做准备。体验课不是知识灌输，而是『体验+激发+预判』。'),
  (4, 'practice', '家长说：『体验课才30分钟，能学到什么？』顾问应如何回应？', '["『确实学不到什么，主要是让您看看我们的老师。』","『学习是慢慢积累的过程！这堂课围绕具体思维方法设计，孩子能初步掌握这个方法，解决1-2个实际问题。更重要的是体验线上互动模式、激发学习兴趣，同时我们会根据表现结合后续自评题精准匹配正式课内容，让学习更有针对性。』","『30分钟足够学会很多知识了，您放心。』","『时间长短不重要，主要看孩子认不认真。』"]', 1, '① 先肯定『学习是慢慢积累的过程』（降低家长对短期效果的过高期待）；② 说明具体收获（掌握一个思维方法+解决1-2个问题）；③ 强调体验价值（体验形式、激发兴趣）；④ 衔接后续服务（根据表现+自评题精准匹配）。这种回应既诚实又有价值感，避免过度承诺或贬低体验课价值。'),
  (4, 'practice', '正式课前安排的10道思维能力自评题的作用是什么？', '["只是形式，没有实际作用","根据答题情况精准判断孩子思维水平，匹配对应学习阶段和适合的老师，确保难度适配","用来筛选优秀学生","作为入学考试，不合格不能报名"]', 1, '10道思维自评题的核心作用：『根据小朋友的答题情况，精准判断他的思维水平，再匹配对应的学习阶段和适合的老师，确保正式课的难度刚好适配孩子』。这是VIPTHINK『精准教学』的核心卖点，顾问需要让家长理解这不是『考试』，而是『匹配工具』，目的是避免孩子跟不上或觉得太简单。'),
  (4, 'practice', '家长问：『你们怎么知道孩子适合哪个阶段？』顾问应如何展示专业度？', '["『凭经验判断，看孩子年龄就行。』","『正式课前我们会安排10道思维能力自评题，根据答题情况精准判断孩子的思维水平，再匹配对应的学习阶段和适合的老师，确保难度刚好适配，不会出现跟不上或太简单的情况。』","『让孩子上一节试听课，老师看看就知道了。』","『根据学校成绩单来安排。』"]', 1, '通过10道思维能力自评题『精准判断思维水平→匹配学习阶段→匹配适合的老师→确保难度适配』。这体现了VIPTHINK的科学性和个性化，与『凭年龄判断』或『看成绩单』形成差异化优势。顾问要强调『精准』和『适配』两个关键词。'),
  (4, 'practice', '正式课分为几个阶段？每个阶段包含多少堂课？', '["6个阶段，每个阶段48堂课","9个阶段，每个阶段24个专题、每个专题4堂课，共96堂课","12个阶段，每个阶段24堂课","3个阶段，每个阶段100堂课"]', 1, '说明：『正式课按孩子的思维水平和学习进度分为9个阶段，从幼稚园3岁启蒙开始到国小6年级进阶提升都有覆盖。每个阶段24个专题，每个专题4堂课，一共是96堂课』。顾问需要准确记忆这些数据，在家长询问时快速、专业地回应。'),
  (4, 'practice', '家长问：『正式课要学多久？每个阶段怎么安排的？』顾问应如何介绍？', '["『要学很多年，具体我也不清楚。』","『正式课分为9个阶段，从幼稚园3岁启蒙到国小6年级都有覆盖。每个阶段24个专题，每个专题4堂课，一共96堂课。课前会通过10道自评题确定起始阶段，后续也会根据学习情况灵活调整，确保学有所获。』","『每个阶段都是固定的，不能调整。』","『学多久看孩子自己，我们不管进度。』"]', 1, '：① 清晰说明阶段数量（9个阶段）和覆盖范围（3岁启蒙到国小6年级）；② 详细说明每个阶段的结构（24专题×4堂课=96堂）；③ 强调灵活性（通过自评题确定起始阶段，根据学习情况灵活调整）；④ 以『确保学有所获』收尾。这种回答既专业又让家长感受到『个性化』和『灵活性』。'),
  (4, 'practice', '正式报名后，教材和教具如何提供？', '["需要家长另外购买实体教材","免费提供对应阶段的电子教材，通过LINE发送，包含课前预习、课后总结、知识点总结、课后练习指导、计算专项练习等","不提供任何教材","只提供纸质教材，没有电子版本"]', 1, '文档明确说明：『正式报名后，我们会免费提供对应阶段的电子教材，授课老师和班导师会通过LINE发给您，包含但不限于课前的预习，课后的总结，课堂知识点总结、课后练习指导，以及一些计算专项练习等内容』。这是配套服务的重要卖点，顾问需要强调『免费』、『电子』、『全面』、『通过LINE便捷获取』等关键词。'),
  (4, 'practice', '正式课的退费政策是什么？', '["一经报名，概不退费","前4堂是无忧试学期，期间可随时申请全额退费；超过4堂随学随退，剩多少退多少，无任何手续费","只能退50%费用","需要扣除30%手续费才能退费"]', 1, '明确退费政策：『前4堂是无忧试学期，期间如果觉得不适合，随时可以申请退费，全额给您退刷。超过4堂的话是随学随退，剩多少退多少，没有任何手续费。退费流程很简单，联系我们提交退费申请即可，审核通过后7-14个工作日内退款会原路返回』。这是消除家长顾虑的核心保障，顾问必须准确传达。'),
  (4, 'practice', '家长说：『万一报名后觉得不合适怎么办？』顾问应如何回应？', '["『那没办法，钱已经交了就不能退了。』","『完全可以退费！我们有明确的退费保障政策：前4堂是无忧试学期，期间随时可申请全额退费；超过4堂随学随退，剩多少退多少，没有任何手续费。流程很简单，提交申请后7-14个工作日内原路返回，我们也会全程跟进进度。让您完全没有后顾之忧。』","『您可以先报少一点课时，这样损失小。』","『一般不会有这种情况，您放心。』"]', 1, '① 直接肯定『完全可以退费』（消除恐惧）；② 详细说明退费政策（前4堂全额退+超过4堂随学随退+无手续费）；③ 说明流程简单和时间（7-14个工作日原路返回）；④ 强调全程跟进服务；⑤ 以『让您完全没有后顾之忧』收尾。这是典型的『风险逆转』话术，将家长的最大顾虑转化为信任点。'),
  (4, 'practice', '正式课缺课后如何补课？', '["不能补课，缺课就错过了","可以看回放补课，也可以提前联系班导老师预约合适补课时间，补课内容与正式课完全一致，补课后老师会发送知识点总结和练习","只能看录像回放，不能上补课","需要额外付费才能补课"]', 1, '『可以看回放补课，或者提前联系班导老师预约合适的补课时间，补课的内容和正式课完全一致，不会影响孩子的学习进度。而且补课后，老师会把补课的知识点总结和练习发给您，确保孩子能跟上』。顾问需要强调『提前预约』、『内容一致』、『不影响进度』、『课后发送总结』等细节，体现服务的完整性。'),
  (4, 'practice', '正式课的上课时间安排有什么特点？', '["时间完全固定，不能选择","可以根据家长需求选择固定时段，一旦确定后就是固定的老师和同学","每次上课时间和老师都是随机的","只能在周末上课"]', 1, '『正式课的上课时间可以根据您的需求选择固定时段，比如每周二和周四晚上7点，一旦确定后就是固定的老师和同学。老师熟悉孩子思维基础，同学长期结伴，课堂节奏稳定，孩子学起来更投入、进步看得见。』。这种『固定时段+固定老师+固定同学』的模式是VIPTHINK的重要卖点，能给孩子稳定的学习环境和同伴关系，顾问需要强调这一点。'),
  (4, 'practice', '家长问：『上课时间能配合我们的时间吗？』顾问应如何回应？', '["『时间都是固定的，您只能配合我们。』","『上课时间可以根据您的需求选择固定时段，比如每周二和周四晚上7点，一旦确定后就是固定的老师和同学，孩子能建立稳定的学习节奏和同伴关系。如果临时有事缺课，也可以提前联系班导预约补课，完全不用担心。』","『时间很灵活，您想什么时候上就什么时候上。』","『时间需要跟老师商量，不一定能配合。』"]', 1, '① 说明可选择性（根据需求选择固定时段）；② 举例说明（如每周二四晚上7点）；③ 强调稳定性优势（固定老师和同学，建立稳定学习节奏）；④ 补充灵活性（临时有事可补课）。这种回答既体现了『个性化选择』，又强调了『稳定性价值』，还补充了『灵活性保障』，全面消除家长顾虑。'),
  (4, 'practice', '家长问：『报名后有问题找谁？』顾问应如何介绍服务团队？', '["『找我就行，其他不管。』","『报名后会实行「3+1」学习跟进服务：班导老师负责上课安排、学情反馈、问题沟通；授课老师负责课后答疑、预习复习指导、作业批改。孩子有任何学习问题，随时通过LINE联系授课老师，老师会及时回复解答，确保学习不脱节。』","『有问题发邮件，老师看到会回复。』","『只有上课老师，没有专门的服务人员。』"]', 1, '① 明确服务模式（『3+1』学习跟进服务）；② 清晰分工（班导老师管安排和沟通，授课老师管答疑和批改）；③ 强调便捷性（随时通过LINE联系）；④ 承诺响应（及时回复解答）；⑤ 以『确保学习不脱节』收尾。这种介绍让家长感受到『专业分工』和『全程陪伴』，增强报名信心。'),
  (4, 'practice', '家长说：『课后作业多不多？我没时间陪孩子做作业。』顾问应如何回应？', '["『作业挺多的，您最好抽时间陪一下。』","『课后作业是少量针对性的练习，一般10-15分钟就能完成，形式很有趣，比如游戏闯关、互动练习，不需要家长花很多时间陪同。作业有详细指导说明，孩子可以独立完成，遇到问题可以联系授课老师解答。如果家长想参与，也可以一起完成亲子练习，增进亲子关系。』","『作业不多，但最好家长监督完成。』","『我们不布置作业，上课就够了。』"]', 1, '① 消除顾虑（少量针对性练习，10-15分钟完成）；② 强调趣味性（游戏闯关、互动练习）；③ 说明独立性（不需要家长花很多时间陪同，孩子可独立完成）；④ 提供支持（遇到问题联系授课老师）；⑤ 升华价值（亲子练习增进关系）。这种回应完美解决了家长『怕累』和『怕没时间』的双重顾虑。'),
  (4, 'practice', '体验课和正式课是否都可以看回放？', '["只有正式课可以看回放","体验课和正式课都可以看回放，方便孩子复习","都不能看回放","只有付费后才能看回放"]', 1, '『我们的体验课和正式课是一样的是可以看回放的，小朋友有什么没有学懂的都通过课程回放复习，那后续正式课也可以跟我们的老师预约视讯一对一讲解』。这是重要的服务卖点，顾问需要强调『体验课和正式课一样享有回放权』，体现一视同仁的服务态度。'),
  (4, 'practice', '家长问：『孩子上课没听懂怎么办？』顾问应如何回应？', '["『没听懂就没办法了，下次上课注意听。』","『不用担心！我们的体验课和正式课都可以看回放，小朋友有什么没学懂的可以通过课程回放复习。后续正式课也可以跟老师预约视讯一对一讲解，确保孩子真正掌握。』","『让孩子自己看课本复习。』","『没听懂说明孩子不适合这个课程。』"]', 1, '① 提供回放资源（体验课和正式课都可以看回放）；② 说明复习方式（通过回放复习）；③ 升级服务（预约视讯一对一讲解）；④ 以『确保孩子真正掌握』收尾。这种回应将『没听懂』的负面情况转化为展示服务完善性的机会，增强家长信心。'),
  (4, 'practice', '家长说：『体验课内容孩子觉得太难了。』顾问应如何回应？', '["『那说明孩子不适合我们的课程。』","『没关系！体验课核心是感受上课形式，内容难度只是参考。如果觉得难，老师会马上调整节奏，把难点拆分成更简单的小问题，用更直观方式讲解。而且这个反馈能帮我们预判孩子水平，后续正式课前的10道自评题会进一步精准定位，匹配最适合的阶段和老师，保证正式课难度刚好适配。』","『让孩子多预习就不觉得难了。』","『难一点才有挑战性，对孩子好。』"]', 1, '① 降低焦虑（体验课核心是感受形式，难度只是参考）；② 说明即时调整（老师拆分难点、用更直观方式讲解）；③ 强调反馈价值（帮助我们预判水平）；④ 衔接后续服务（10道自评题精准定位）；⑤ 承诺结果（匹配最适合的阶段和老师，保证难度适配）。这种回应将『负面反馈』转化为『正面信号』，展示专业性和服务体系。'),
  (4, 'practice', '体验课和正式课的班型人数是多少？', '["1对1教学","6-8人小班制","20-30人大班","50人以上直播课"]', 1, '『我们后续的正式课是2人就可以开班，上限是6/8人，这个人数既能保证课堂互动氛围，又能让老师兼顾到每个孩子』。顾问需要强调6-8人小班的优势：① 保证互动氛围；② 老师能兼顾每个孩子；③ 每个孩子都有充足发言机会；④ 老师能实时关注课堂状态并调整引导方式。'),
  (4, 'practice', '家长说：『线上课一个老师带那么多孩子，能顾得过来吗？』顾问应如何回应？', '["『确实有点多，但老师尽力了。』","『我们后续的正式课是2人就可以开班，上限是6/8人，这个人数既能保证课堂互动氛围，又能让老师兼顾到每个孩子。每个孩子在课堂上都有充足的发言机会，老师会特意引导每个孩子分享思路和答案。而且小班制能让老师实时关注每个孩子的课堂状态，及时调整引导方式，确保每个孩子都能充分体验并有所收获。』","『老师很专业，再多孩子也能管好。』","『您可以选择1对1，但价格贵很多。』"]', 1, '① 明确班型（6-8人小班制）；② 说明人数优势（既保证互动氛围，又能兼顾每个孩子）；③ 强调发言机会（每个孩子有充足发言机会，老师特意引导分享）；④ 说明实时关注（关注课堂状态，及时调整引导方式）；⑤ 以『确保每个孩子都能充分体验并有所收获』收尾。这种回应用具体细节消除『顾不过来』的顾虑。'),
  (4, 'practice', '孩子上课过程中一直不发言，老师如何处理？', '["老师忽略这个孩子，专注其他学生","老师会用更温和、简单的问题主动引导，比如先问『您觉得这个答案是对的吗？』慢慢鼓励孩子开口；小班氛围也会带动他","直接点名批评孩子不发言","让家长把孩子带离课堂"]', 1, '『我们的老师会注意到这种情况，会用更温和、简单的问题主动引导孩子，比如先问「您觉得这个答案是对的吗？」「要不要试试说说你的想法？」，慢慢鼓励孩子开口。而且小班制的氛围很轻松，其他小朋友的积极发言也会带动他』。顾问需要强调『温和引导』、『循序渐进』、『同伴带动』三个关键词，让家长放心。'),
  (4, 'practice', '家长说：『孩子上课一直不发言，是不是没听懂？』顾问应如何回应？', '["『是的，没听懂所以不敢发言。』","『不用太担心！孩子不发言可能是还在适应课堂氛围，或者性格比较内向，不一定是没听懂。我们的老师会主动用温和、简单的问题引导他，比如先问「您觉得这个答案是对的吗？」慢慢鼓励开口。小班氛围很轻松，其他小朋友也会带动他。体验课主要是感受形式，就算暂时不发言也没关系，后续正式课前的自评题和老师匹配会更精准贴合孩子的性格和水平。课后我也会让老师把详细表现反馈给您。』","『孩子太害羞了，需要多锻炼。』","『不发言会影响学习效果，您要多鼓励孩子。』"]', 1, '① 消除焦虑（不用太担心，不一定是没听懂）；② 分析原因（适应氛围或性格内向）；③ 说明老师应对（温和引导、简单问题、慢慢鼓励）；④ 强调环境作用（小班氛围轻松，同伴带动）；⑤ 降低压力（体验课主要是感受形式，暂时不发言没关系）；⑥ 衔接后续服务（自评题和老师匹配更精准）；⑦ 承诺反馈（课后让老师详细反馈）。这种回应全面安抚家长，展示专业度和关怀。'),
  (4, 'practice', '线上课堂如何监督孩子是否分心？', '["完全靠家长监督","老师通过实时连麦、随机提问、课堂答题等方式随时关注状态，发现分心及时拉回；家长也可在旁边配合提醒","安装监控软件监控孩子","分心就踢出课堂"]', 1, '文档明确说明：『老师会通过实时连麦、随机提问、课堂答题等方式，随时关注孩子的状态，一旦发现孩子分心，会及时用有趣的话题或孩子感兴趣的内容把注意力拉回来。另外，家长也可以在旁边稍微提醒一下，配合老师让孩子专注上课』。顾问需要强调『技术互动手段+老师主动引导+家长配合』的三层监督机制。'),
  (4, 'practice', '家长说：『线上上课孩子容易分心玩其他东西，老师能管到吗？』顾问应如何回应？', '["『线上课确实管不住，主要靠您家长监督。』","『我们有专门的互动监督机制！老师会通过实时连麦、随机提问、课堂答题等方式随时关注孩子状态，一旦发现分心，会及时用有趣的话题把注意力拉回来。另外，家长也可以在旁边稍微提醒一下，配合老师让孩子专注上课，慢慢养成良好的上课习惯。』","『孩子分心是因为课程不够有趣。』","『我们没办法，只能建议您选线下课。』"]', 1, '① 明确机制（专门的互动监督机制）；② 具体手段（实时连麦、随机提问、课堂答题）；③ 应对方式（发现分心及时用有趣话题拉回注意力）；④ 家长配合（在旁边稍微提醒，配合老师）；⑤ 长期目标（慢慢养成良好上课习惯）。这种回应展示了对问题的重视和完善的解决方案，而非推卸责任。'),
  (4, 'practice', '家长说：『体验课当天就要决定吗？太赶了。』顾问应如何回应？', '["『对，当天必须决定，过期不候。』","『不用当天决定哦！体验课结束后优惠活动会保留24/48小时，24/48小时内报名都能享受专属折扣和相关福利。这24/48小时里您可以和家人商量，也可以让孩子完成正式课前的10道思维能力自评题，我会随时为您解答疑问。24/48小时后优惠过期恢复原价，所以如果适合孩子，建议24/48小时内报名避免错过。』","『您慢慢考虑，不急。』","『优惠随时都有，不用赶。』"]', 1, '文档话术结构：① 消除压力（不用当天决定）；② 明确时间窗口（48小时内享受优惠）；③ 建议利用时间（和家人商量、完成自评题等结果）；④ 承诺服务（随时解答疑问）；⑤ 制造紧迫感（24/48小时后过期恢复原价）；⑥ 建议行动（适合的话建议24/48小时内报名）。这种回应既给了家长思考空间，又保持了推进转化的张力。'),
  (4, 'practice', '体验课学员报名正式课除了折扣外，还有哪些额外福利？', '["只有折扣，没有其他福利","减免XX台币报名费+参与打卡活动额外赠送X节课","免费赠送实体教材","赠送线下课程"]', 1, '『还能减免XX台币的报名费。另外，现在报名正式课，还能参与打卡活动，完成打卡后额外赠送X节课』。顾问需要将这些福利叠加展示，让家长感受到『多重优惠』的价值，提升报名意愿。'),
  (4, 'practice', '家长说：『你们的课程太贵了。』顾问应如何回应？', '["『不贵啊，已经很便宜了。』","『您说得对，教育投资确实需要慎重考虑。不过您可以算笔账：平均一节课大概330台币，不到一顿下午茶的钱。但孩子学到的是能受益一辈子的逻辑思维、问题解决能力。而且我们有前4堂无忧试学期，不合适全额退费；超过4堂随学随退，没有任何手续费。相当于零风险尝试。您现在犹豫的时间，可能正是别人家孩子进步的时间呢。』","『那您去别家看看吧，我们价格没法降。』","『贵有贵的道理，我们老师好。』"]', 1, '这是经典的『价格异议处理』话术：① 共情认同（您说得对，教育投资需要慎重）；② 成本拆解（一节课330台币，不到下午茶的钱）；③ 价值升华（学到受益一辈子的能力）；④ 风险逆转（前4堂无忧试学+随学随退）；⑤ 紧迫感（您犹豫的时间正是别人家孩子进步的时间）。避免直接说『不贵』或『去别家』，而是用『价值+保障+紧迫感』组合回应。'),
  (4, 'practice', '当家长说『要考虑一下』时，顾问应该如何判断真实顾虑？', '["直接说『好的，您考虑清楚联系我』然后结束对话","用假设成交法询问：『如果现在就报名，您觉得最担心的是哪一点？是怕课程效果不好，还是时间安排不过来？』并举例类似家长的顾虑和解决方案","不断催促家长尽快决定","直接给更大的折扣"]', 1, '客户说『考虑一下』90%是有顾虑但不好意思说。要用『假设成交+具体选项』的方式挖出真实顾虑，比如『是怕课程效果不好，还是时间安排不过来？』，并举例真实案例增加可信度。直接放弃或催促都是错误的，给更大折扣则可能让家长觉得『还有空间可以谈』。'),
  (4, 'practice', '家长说：『我再考虑考虑。』顾问应如何推进？', '["『好的，您考虑清楚再联系我。』","『XX妈妈，我特别理解，给孩子报班是大事，肯定要多对比。不过我想请教您：如果现在就报名，您觉得最担心的是哪一点？是怕课程效果不好，还是时间安排不过来？其实上周有位家长也说「考虑」，后来她担心孩子坐不住。结果体验课上孩子跟着老师做游戏学数学，下课还不想走。您看要不要也让孩子完成自评题，看看适配情况再决定？就算暂时不报，也能更了解孩子的情况。』","『别考虑了，今天报名最划算。』","『那我每天打电话问您考虑得怎么样。』"]', 1, '这是标准的『考虑型异议』处理话术，结构为：① 共情理解（我特别理解，给孩子报班是大事）；② 假设成交+给选项（如果现在就报名，最担心哪一点？是A还是B？）；③ 真实案例（上周有位家长也担心…结果…）；④ 降低门槛（完成自评题看看适配情况，就算不报也能了解孩子）；⑤ 给台阶下（不强迫立即成交，但推进下一步行动）。'),
  (4, 'practice', '在价格谈判中，顾问应避免哪些致命误区？', '["上来就推课，把破冰变成推销；客户拒绝就慌，不敢追问真实顾虑；成交后就失联","只讲课程特点，不讲家长利益","直接反驳家长说『贵』","以上都是"]', 3, '根据实际，课程顾问的三大致命误区是：① 上来就推课，把破冰变成推销；② 客户拒绝就慌，不敢追问真实顾虑；③ 成交后就失联。在价格谈判中还要避免：只讲课程特点不讲家长利益、直接反驳家长说『贵』、虚假促销等。所有选项描述的都是应避免的错误做法，因此选D。'),
  (4, 'practice', '家长说：『别家机构更便宜。』顾问应如何回应？', '["『那您去别家吧，我们没法降价。』","『XX妈妈，我特别理解您对价格的考虑。其实我们刚做顾问时也觉得价格要对比，后来很多家长反馈：选机构最怕的是花了钱没效果，孩子浪费的时间买不回来。我们平均330台币一节课，包含6-8人小班互动、专属老师跟进、课后答疑、电子教材、回放复习，还有前4堂无忧试学保障。您可以算算，这些服务单独买要多少钱？而且我们是专门服务台湾学员的，老师都学习过本地孩子的学习习惯和思维特点。效果和服务才是真的划算。』","『我们马上给您申请更低价格。』","『便宜没好货，您懂的。』"]', 1, '这是『竞品对比』话术，结构为：① 共情理解；② 转移焦点（从价格对比到价值对比）；③ 成本拆解+服务罗列（330台币包含哪些服务，单独买要多少钱）；④ 差异化优势（专门服务台湾学员，熟悉本地学习习惯）；⑤ 价值总结（效果和服务才是真的划算）。避免贬低竞品或立即降价，而是用『价值叠加』让家长重新评估『性价比』。'),
  (4, 'practice', '顾问在介绍价格时，应该采用什么策略让家长觉得『值』而不是『贵』？', '["直接说『我们不贵』","把总价拆成每日小成本，对比不报名的损失，强调附加价值","只报总价，不解释","先报高价再打折"]', 1, '根据培训资料，客户觉得『贵』是因为『付出的钱』和『得到的价值』不匹配。正确策略是：① 把总价拆成小成本（如每天不到一杯奶茶钱）；② 对比不报名的机会成本（孩子问题不解决的后果）；③ 强调附加价值（包含哪些服务，单独买要多少钱）。永远不要说『我们不贵』，而要说『您得到的是…』。'),
  (4, 'practice', '家长问：『能不能再便宜一点？』顾问应如何回应？', '["『我去申请一下，看能不能打折。』","『XX妈妈，价格已经是体验课学员的专属优惠了，48小时后就会恢复原价。不过我可以帮您算笔账：平均300台币一节课，包含小班互动、专属老师、课后答疑、电子教材、课程回放，还有前4堂无忧试学。您想想，孩子现在数学思维基础打好了，以后面对学校难题都能快速找到方法，省下的补习时间和焦虑情绪，值多少钱？而且打卡还能额外赠课，算下来每节课更划算。』","『不能便宜了，这是最低价。』","『您报更多课时我可以申请折扣。』"]', 1, '这是『砍价』话术，结构为：① 确认价格已优惠（已经是专属优惠，48小时后恢复原价）；② 成本拆解（300台币包含哪些服务）；③ 价值升华（思维基础打好后的长期收益）；④ 额外福利（打卡赠课）；⑤ 不直接拒绝降价，但用价值让家长『自己说服自己』。避免立即说『去申请』或『不能便宜』，而是把谈判焦点从『价格』转移到『价值』。'),
  (4, 'practice', '在成交阶段，顾问应使用哪种方法推进签约？', '["直接问『您要不要报名？』","使用二选一法则（『您是选周二四的班，还是一三五的班？』）或假设成交法（直接拿出协议填写）","等待家长主动提出报名","不断强调再不报名就没名额了"]', 1, '成交阶段最佳策略是：① 二选一法则（给家长选择A或B，而不是『要或不要』）；② 假设成交法（直接拿出入学协议填写，用行动代替追问）。这两种方法能让家长在框架内做出选择，降低决策压力。直接问『要不要』容易被拒绝，等待家长主动则错失时机，虚假紧迫感会摧毁信任。'),
  (4, 'practice', '体验课结束后，顾问应该如何推进家长报名？', '["『您考虑好了吗？要不要报名？』","『XX妈妈，根据孩子刚才的表现和老师的反馈，我觉得XX阶段非常适合他。您看是选择周二和周四晚上7点的班，还是周一和周三晚上7点？这两个时段都是金牌老师授课，名额都不多了。另外48小时内报名还能享受专属折扣和赠课福利，我先帮您预留一个名额，您看哪个时间更合适？』","『今天不报名就没优惠了。』","『我明天再打电话问您。』"]', 1, '这是标准的『关单话术』，结构为：① 基于专业判断推荐（根据表现和反馈，XX阶段适合）；② 二选一法则（周二四还是周一三？）；③ 附加价值（金牌老师授课，名额不多）；④ 紧迫感（48小时内专属折扣和赠课）；⑤ 假设成交（先帮您预留名额）；⑥ 再次二选一（您看哪个时间更合适？）。整个话术没有一句『要不要报名』，但每一步都在推进成交。'),
  (4, 'practice', '成交后顾问应如何进行预期管理，避免后续退费？', '["承诺孩子第一节课就能提分20分","提前说明学习是循序渐进的过程，体验课是感受形式，正式课通过自评题精准匹配后循序渐进提升，避免家长期望过高","什么都不说，让家长自己体会","承诺一个月就能学完所有阶段"]', 1, '根据实际经验，很多退费不是因为课程不好，而是客户预期太高。正确的预期管理是：提前说明学习是循序渐进的过程，体验课主要是感受形式，正式课通过自评题精准匹配后循序渐进提升。避免过度承诺（如第一节课提分20分、一个月学完所有阶段），也避免完全不沟通期望。'),
  (4, 'practice', 'VIPTHINK支持哪些支付方式？', '["仅支持现金支付","卡支付（Visa、Mastercard等）、LINE Pay（但不推荐，因LINE钱包会收取手续费）","仅支持银行转账","仅支持支付宝"]', 1, '『选择卡支付（Visa、Mastercard）等等、LINE Pay（如果是这个支付会后line钱包会收取手续费，不推荐）』。'),
  (4, 'practice', '支付页面显示美金，家长付款时如何换算？是否有额外手续费？', '["家长需要手动换算，会收取额外手续费","付款时自动根据当天汇率换算成新台币扣除，不会有额外的换算手续费","固定汇率1:30换算","不换算，直接扣美金"]', 1, '『支付页面统一显示为美金哦，但付款时会自动根据当天的汇率换算成新台币扣除，不会有额外的换算手续费呀～因为现在新台币也一直在涨，可以帮妈咪您省一些钱～』。顾问需要强调『自动换算』、『无额外手续费』、『新台币上涨省钱』三个利好点，消除家长对汇率和手续费的顾虑。'),
  (4, 'practice', '在线支付成功后多久到账？何时可以排课？', '["需要3-5个工作日到账，下周才能排课","在线支付成功后即时到账；支付完成后截图发给顾问跟进，确认首课时间即可马上上课","需要一个月才能到账","到账后才能申请排课，流程很长"]', 1, '文档明确说明：『在线支付（卡、LINE Pay等）成功后是即时到账；您支付完成后可以截图发给我，我帮您跟进到账情况…您只要确认首课时间就可以马上上课啦』。顾问需要强调『即时到账』和『确认首课时间即可马上上课』，让家长感受到高效便捷的服务。'),
  (4, 'practice', '家长问：『支付后多久能上课？』顾问应如何回应？', '["『要等一周审核，审核通过才能排课。』","『在线支付成功后是即时到账的。您支付完成后截图发给我，我帮您跟进到账情况。我们有专门的教务老师对接排课，您可以跟教务老师确认首课时间就可以马上上课。』","『支付后还要等教材寄到才能上课。』","『大概要一个月才能排上课。』"]', 1, '① 说明到账速度（即时到账）；② 跟进服务（截图发给顾问，帮您跟进）；③ 介绍排课流程（专门教务老师对接，发送现有班级）；④ 操作便捷（确认首课时间即可马上上课）；⑤ 灵活选择（发两个合适时间或直接与教务沟通）。这种回应展示了高效、灵活、专业的服务流程。'),
  (4, 'practice', '支付时顾问应如何消除家长对隐藏费用的担忧？', '["『可能有其他费用，到时候再说。』","明确告知没有任何隐藏费用，退费规则写在合约里，可以开扩音手把手指导支付","『隐藏费用是行业惯例，我们也不例外。』","『您先付了再说，有问题再退。』"]', 1, '『我们没有任何隐藏费用！退费的规则也是有写在合约里的，您放心。妈咪您要是担心可以开着扩音，我带着您支付，那过程中有任何支付疑问，都可以随时问我』。顾问需要：① 明确承诺（没有任何隐藏费用）；② 凭证说明（退费规则写在合约里）；③ 提供陪伴服务（开扩音手把手指导）；④ 承诺即时解答（有任何疑问随时问我）。'),
  (4, 'practice', '家长说：『支付时会不会有隐藏费用？』顾问应如何回应？', '["『您放心，不会有隐藏费用的。』","『我们没有任何隐藏费用，退费的规则也都写在合约里，您可以放心查看。如果您担心操作问题，可以开着扩音，我一步一步带着您支付，过程中有任何支付疑问都可以随时问我，我会帮您解答。』","『所有费用都列出来了，您自己看。』","『隐藏费用多少有一点，但不多。』"]', 1, '文档话术结构：① 明确承诺（没有任何隐藏费用）；② 凭证支持（退费规则写在合约里）；③ 主动陪伴（开扩音一步一步带着支付）；④ 承诺支持（有任何疑问随时问我，帮您解答）。这种回应既消除了顾虑，又展示了『手把手服务』的贴心态度，增强信任感。'),
  (4, 'practice', '支付完成后，顾问应如何完成服务交接？', '["『钱收到了，您等上课通知吧。』","『支付完成了！我现在同步发给您教务老师、班导老师和授课老师的LINE ID。教务老师负责对接排课，班导老师负责学情反馈和上课安排沟通，授课老师负责课后答疑和作业批改。孩子有任何学习问题，随时可以通过LINE联系授课老师。我们会持续跟进孩子的学习情况，有任何问题随时找我们！』","『支付完了，我没别的事了。』","『您自己加老师吧，ID在官网上。』"]', 1, '确认支付完成了！在line上 发送预设信息包括了：①lineID（教务、班导、授课老师的LINE ID）；②解释分工（教务排课、班导反馈沟通、授课答疑批改）；③强调便捷（随时通过LINE联系）；④ 持续承诺（我们会持续跟进，有任何问题随时找我们）。这种交接让家长感受到『不是一锤子买卖，而是长期服务』，为后续转介绍奠定基础。');
